INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('8600220b0e4440a9b142088174871f172e2ad93c1d05a4b70277cb6332f23e65','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2025','Q.1(a)','Define the cell theory and state its seven fundamental principles.','\\text{Define the cell theory and state its seven fundamental principles.}','Cell theory is the fundamental biological principle stating that cells are the basic structural, functional, and organizational units of all living organisms. While traditionally described by three tenets, modern biology recognizes seven fundamental principles: 1. All living organisms are composed of one or more cells. 2. The cell is the basic unit of life. 3. All cells arise from pre-existing cells via division (biogenesis). 4. Cells contain hereditary information (DNA) which is passed to daughter cells during division. 5. All cells are fundamentally similar in chemical composition and metabolic activities. 6. Energy flow (metabolism and biochemistry) occurs within cells. 7. The activity of an organism depends on the total activity of independent cells.','\\text{Cell theory posits that the cell is the fundamental unit of life. Its seven principles are:} \\\\ 1. \\text{All living organisms are composed of one or more cells.} \\\\ 2. \\text{The cell is the basic structural and functional unit of all life.} \\\\ 3. \\text{Cells arise only from pre-existing cells through cell division.} \\\\ 4. \\text{Cells contain hereditary material (DNA) passed to offspring.} \\\\ 5. \\text{All cells are similar in chemical composition and metabolic processes.} \\\\ 6. \\text{Energy flow occurs within the cell (metabolism).} \\\\ 7. \\text{The activity of an entire organism is the result of the integrated activities of its constituent cells.}','The cell theory establishes the cell as the primary unit of life, governed by the seven principles of structural composition, functional unit, biogenesis, heredity, chemical similarity, metabolic energy flow, and collective organismal activity.','["Cell Biology", "Cell Theory"]','conceptual','0.98',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('11a5ac79a849aab832769f372862a2237aa323694cc4750caa90d6e54ffad76b','Mid Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.1(b)','Draw a schematic diagram of Bioreactor. Describe any three major applications of bioreactor in Biotechnology.','\\text{Draw a schematic diagram of Bioreactor. Describe any three major applications of bioreactor in Biotechnology.}','Step 1: Conceptual Analysis of a Bioreactor. A bioreactor is a vessel designed to maintain an optimal environment for biological processes (such as cell cultures or fermentation). Key components include an impeller for mixing, a motor, a sparger for aeration, cooling jackets for temperature control, and sensors for monitoring pH and dissolved oxygen. Step 2: Schematic Representation. The structure involves a cylindrical vessel with an inlet for media, a gas sparger at the bottom, an agitation system (impeller), and ports for monitoring and output. Step 3: Applications. 1. Pharmaceutical Production: Large-scale production of recombinant proteins and antibiotics. 2. Food Industry: Production of enzymes, organic acids, and fermented beverages. 3. Waste Treatment: Bioremediation using microorganisms to break down industrial or municipal pollutants.','\\text{A bioreactor consists of a cylindrical vessel with the following components: } \\\\ \\text{1. Impeller: For uniform mixing.} \\\\ \\text{2. Sparger: For O2 supply.} \\\\ \\text{3. Temperature Control Jacket: To maintain homeostasis.} \\\\ \\text{4. Sensors: For pH and dissolved oxygen monitoring.} \\\\ \\text{Applications:} \\\\ \\text{1. Pharmaceutical Industry: Production of insulin, vaccines, and antibiotics.} \\\\ \\text{2. Industrial Biotechnology: Synthesis of enzymes and organic acids (e.g., citric acid).} \\\\ \\text{3. Environmental Biotechnology: Bioremediation of toxic waste via microbial degradation.}','Bioreactors are used for 1. Pharmaceutical protein production, 2. Industrial fermentation, and 3. Environmental bioremediation.','["Bioreactor", "Biotechnology"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('ac14b112655ecf693019cd15105066545d01177b7253c4932cd9325c9fdd2413','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2025','Q.2(a)','Describe functions of mitochondria and chloroplast in eukaryotic cells.','\\text{Describe functions of mitochondria and chloroplast in eukaryotic cells.}','1. Mitochondria: Often called the powerhouses of the cell, their primary function is to perform cellular respiration. This process involves the oxidation of nutrients, such as glucose, to produce adenosine triphosphate (ATP), which serves as the primary chemical energy currency for the cell. 2. Chloroplasts: These organelles are found in plants and algae and are the sites of photosynthesis. They convert light energy into chemical energy by capturing photons to drive the synthesis of glucose from carbon dioxide and water, releasing oxygen as a byproduct. 3. Comparison: While mitochondria facilitate the breakdown of complex molecules to release energy (catabolism), chloroplasts facilitate the assembly of molecules to store energy (anabolism). Both organelles are semi-autonomous and contain their own DNA.','\\text{1. Mitochondria function as the primary sites of cellular respiration, facilitating the process: } C_6H_{12}O_6 + 6O_2 \\rightarrow 6CO_2 + 6H_2O + \\text{ATP}. \\text{ They utilize the Krebs cycle and electron transport chain to maximize ATP yield. 2. Chloroplasts facilitate photosynthesis, represented by: } 6CO_2 + 6H_2O + \\text{light} \\rightarrow C_6H_{12}O_6 + 6O_2. \\text{ This occurs via light-dependent reactions in the thylakoids and the Calvin cycle in the stroma. 3. Energy dynamics: Mitochondria perform oxidative phosphorylation for energy release, whereas chloroplasts perform photophosphorylation for energy storage.}','Mitochondria produce ATP via cellular respiration; Chloroplasts produce glucose via photosynthesis.','["Cell Organelles", "Chloroplast", "Mitochondria", "Programming Concepts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('bbfd4f3b93cbacc972f91c32ea7e30e55495a4e47bbb3bb7b45ef59c39509924','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2025','Q.2(b)','Explain the significance of the Miller-Urey experiment in understanding the origin of life.','\\text{Explain the significance of the Miller-Urey experiment in understanding the origin of life.}','The Miller-Urey experiment is a landmark study in the field of abiogenesis. The conceptual analysis focuses on whether simple, inorganic compounds can transition into complex organic molecules under conditions simulating the primitive Earth. Step 1: Hypothesis formation. Miller and Urey proposed that Earth\'s early atmosphere was reducing, containing methane, ammonia, hydrogen, and water vapor. Step 2: Experimental setup. They created a closed system simulating the cycle of ocean evaporation and lightning strikes (via electrical discharge). Step 3: Analysis of products. After one week, the condensate was analyzed, revealing the presence of amino acids, which are the fundamental building blocks of proteins. Step 4: Interpretation. The experiment proved that organic chemistry can arise from inorganic precursors through natural physical processes, providing empirical support for the Oparin-Haldane hypothesis.','\\text{1. Setup: Closed apparatus simulating early Earth (H}_2\\text{O, CH}_4\\text{, NH}_3\\text{, H}_2\\text{). } \\\\ \\text{2. Mechanism: Electrical sparks provided energy input, simulating lightning to induce chemical reactions. } \\\\ \\text{3. Result: Formation of complex organic molecules (amino acids such as glycine and alanine) from inorganic precursors. } \\\\ \\text{4. Conclusion: Demonstration that life\'s building blocks can emerge via prebiotic chemical evolution.}','The Miller-Urey experiment empirically demonstrated that complex organic molecules can form from simple, inorganic components under prebiotic conditions, establishing a scientific foundation for the study of abiogenesis.','["Miller-Urey Experiment", "Origin of Life"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3d1a449625b07ea03fa0de7ab2a71432c58d356ea1591b92bae28ccd7e99230e','Mid Semester','Unknown Subject (BE24101)','BE24101','4','2025','Q.3(a)','List the key steps involved in the Central Dogma of Molecular Biology.','\\text{List the key steps involved in the Central Dogma of Molecular Biology.}','The Central Dogma of Molecular Biology describes the flow of genetic information within a biological system. It consists of three primary stages: 1. Replication: The process where DNA is duplicated to ensure genetic continuity. 2. Transcription: The process where a specific DNA segment is copied into messenger RNA (mRNA) by RNA polymerase. 3. Translation: The process where the mRNA sequence is decoded by ribosomes to synthesize a specific chain of amino acids, forming a protein.','\\text{The Central Dogma of Molecular Biology comprises the following sequential processes:} \\\\ 1. \\text{Replication: } DNA \\rightarrow DNA \\text{ (Duplication of genetic material)} \\\\ 2. \\text{Transcription: } DNA \\rightarrow RNA \\text{ (Synthesis of mRNA from a DNA template)} \\\\ 3. \\text{Translation: } RNA \\rightarrow \\text{Protein (Synthesis of polypeptides guided by mRNA sequence)}','Replication, Transcription, and Translation.','["Central Dogma", "Molecular Biology"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('eb844b4e63f83079cdf41ecec33d7cd5771998c4a31568f4349bd4a5a8b236aa','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2025','Q.3(b)','Compare prokaryotic and eukaryotic cells in terms of structure and function.','\\text{Compare prokaryotic and eukaryotic cells in terms of structure and function.}','1. Conceptual Analysis: Prokaryotic and eukaryotic cells are the two primary classifications of life. The comparison centers on cellular compartmentalization, genetic material organization, and energy production mechanisms. 2. Structural comparison: Prokaryotes (e.g., bacteria) lack membrane-bound organelles and a nucleus, whereas eukaryotes (e.g., animal/plant cells) contain a nucleus and specialized organelles like mitochondria and ER. 3. Functional comparison: Prokaryotes perform metabolic processes in the cytoplasm or plasma membrane; eukaryotes utilize compartmentalization for specialized chemical reactions, increasing efficiency. 4. Interpretation: The absence of organelles in prokaryotes allows for rapid reproduction and high metabolic flexibility, while eukaryotes allow for greater complexity and multicellularity through specialized regulation.','\\text{Structural Comparison: } \\begin{cases} \\text{Prokaryotes: No nucleus, lack membrane-bound organelles, circular DNA.} \\\\ \\text{Eukaryotes: Membrane-bound nucleus, complex organelles, linear DNA.} \\end{cases} \\\\ \\text{Functional Comparison: } \\begin{cases} \\text{Prokaryotes: Efficient replication, cytoplasmic metabolic pathways.} \\\\ \\text{Eukaryotes: Specialized compartmentalization, mitosis/meiosis, endomembrane system.} \\end{cases} \\\\ \\text{Conclusion: Eukaryotic cells enable multicellular specialization, whereas prokaryotic cells prioritize metabolic speed and simple morphology.}','Prokaryotes lack membrane-bound organelles and a defined nucleus, favoring metabolic speed, while eukaryotes utilize intracellular compartmentalization for higher complexity.','["Cell Structure", "Eukaryotes", "Programming Concepts", "Prokaryotes"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4afec82cf438754c80442ca048a3c634ecac484514cad7d76384cd27d9857dbb','Mid Semester','Unknown Subject (BE24101)','BE24101','4','2025','Q.4(a)','DNA consists of four alphabets (nucleotide bases), while proteins are made up of twenty alphabets (different amino acids). Explain how genetic information flow from DNA to protein.','\\text{DNA consists of four alphabets (nucleotide bases), while proteins are made up of twenty alphabets (different amino acids). Explain how genetic information flow from DNA to protein.}','The flow of genetic information, known as the Central Dogma, proceeds via two primary stages: transcription and translation. Conceptually, the challenge is mapping a 4-base alphabet (A, U, C, G) to a 20-amino acid protein alphabet. A single base (4^1=4) or two bases (4^2=16) are insufficient to uniquely encode 20 amino acids. Therefore, a triplet code (codon) is used, where 4^3 = 64 possible combinations, providing redundancy (degeneracy) for the 20 amino acids. 1. Transcription: DNA is transcribed into messenger RNA (mRNA) in the nucleus, where the gene sequence acts as a template. 2. Translation: In the cytoplasm, ribosomes read the mRNA codons. Transfer RNA (tRNA) molecules with complementary anticodons transport specific amino acids to the ribosome, building the polypeptide chain based on the genetic sequence. The result is the conversion of a nucleotide sequence into a functional protein structure.','The flow of information follows the Central Dogma: \\text{DNA} \\rightarrow \\text{mRNA} \\rightarrow \\text{Protein}. \\\\ 1. \\text{Encoding Problem:} \\text{Given } N=4 \\text{ bases, we seek the minimum length } n \\text{ such that } 4^n \\geq 20. \\text{ Since } 4^2 = 16 < 20 \\text{ and } 4^3 = 64 \\geq 20, \\text{ a triplet code is required.} \\\\ 2. \\text{Transcription:} \\text{RNA polymerase synthesizes mRNA from a DNA template: } (\\text{DNA sequence}) \\xrightarrow{\\text{transcription}} (\\text{mRNA sequence}). \\\\ 3. \\text{Translation:} \\text{Ribosomes interpret mRNA codons. For a codon } C = (b_1, b_2, b_3), \\text{ the matching tRNA anticodon binds, aligning amino acids: } \\sum_{i=1}^{k} \\text{Codon}_i \\xrightarrow{\\text{translation}} \\text{Amino Acid}_i. \\\\ \\text{Interpretation: The genetic code is degenerate, meaning multiple codons may map to the same amino acid, ensuring robustness in biological information transfer.}','Genetic information flows from DNA to protein via transcription into mRNA and translation into a polypeptide chain, utilizing a triplet codon system (4^3=64 combinations) to encode the 20 amino acids.','["Genetic Code", "Protein Synthesis"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('12b9dc9da78499cb0e5dcb258bf3948509e47c840ef6180e41ac5d9f863212af','Mid Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.4(b)','Evaluate the advantages and ethical concerns of genome editing technology.','\\text{Evaluate the advantages and ethical concerns of genome editing technology.}','Step 1: Conceptual analysis. Genome editing (CRISPR-Cas9) allows precise DNA alterations. Advantages include curing genetic diseases and improving agricultural yields. Ethical concerns involve germline editing (heritable changes), off-target effects, and social inequality. Step 2: Analysis of Advantages. Therapeutic potential: Eradicating monogenic disorders like sickle cell anemia. Agricultural potential: Drought resistance and enhanced nutrition. Step 3: Analysis of Ethical Concerns. Safety: Unintended mutations (off-target effects). Equity: Access disparities leading to \'genetic divide\'. Moral status: Germline modifications affect future generations without consent, raising concerns about eugenics. Step 4: Interpretation. The technology offers transformative medical benefits but requires a robust ethical framework, international regulation, and cautious clinical application to balance innovation with human dignity.','\\text{Step 1: Analysis of Advantages. Genome editing offers: (i) Therapeutic Precision: Correction of genetic defects at the source, potentially curing hereditary diseases (e.g., CF, SCID). (ii) Agricultural Productivity: Enhancing crop resilience and nutritional profiles. } \\\\ \\text{Step 2: Analysis of Ethical Concerns. (i) Biosafety: Off-target cleavage poses risks of oncogenic mutations. (ii) Germline Editing: Inheritable changes create long-term uncertainties for the gene pool and the inability to obtain consent from future generations. (iii) Societal Implications: Risk of \'designer babies\' and exacerbated socio-economic inequality. } \\\\ \\text{Step 3: Synthesis. The utility of } \\textit{CRISPR-Cas9} \\text{ systems relies on the balance between medical efficacy and the mitigation of irreversible biological risks.}','Genome editing provides significant therapeutic and agricultural advantages but is constrained by profound ethical dilemmas regarding germline safety, long-term evolutionary impact, and equitable access.','["Bioethics", "Genome Editing"]','analytical','0.98',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('449b019cc71293cd13e911b33115b3c097dbddac0092b72a25bf77f06cefd9c8','Mid Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.5(a)','Explain the steps involved in recombinant DNA technology and mention its applications.','\\text{Explain the steps involved in recombinant DNA technology and mention its applications.}','Recombinant DNA (rDNA) technology involves isolating a specific gene, inserting it into a vector, and introducing it into a host organism for expression. Step 1: Isolation of genetic material (DNA) from the donor cell. Step 2: Fragmentation using restriction endonucleases to create sticky/blunt ends. Step 3: Selection of a vector (e.g., plasmid) and cutting it with the same enzymes. Step 4: Ligation of the donor DNA and vector DNA using DNA ligase to form a recombinant molecule. Step 5: Transformation/Transfection into the host cell (e.g., E. coli). Step 6: Screening and selection of recombinant clones. Step 7: Expression of the target protein. Applications include the production of therapeutic proteins (e.g., insulin), gene therapy, development of transgenic crops for pest resistance, and forensic DNA profiling.','\\text{The process of Recombinant DNA Technology involves the following systematic steps:} \\\\ 1. \\text{Isolation of DNA:} \\text{Extraction of genetic material from the source organism.} \\\\ 2. \\text{Fragmentation:} \\text{Cleavage of DNA using restriction endonucleases (molecular scissors) to generate complementary ends.} \\\\ 3. \\text{Vector Selection and Insertion:} \\text{Cutting a cloning vector (e.g., plasmid) with the same enzyme to create compatibility.} \\\\ 4. \\text{Ligation:} \\text{Joining the gene of interest with the vector using DNA ligase to form recombinant DNA.} \\\\ 5. \\text{Transformation:} \\text{Introduction of recombinant DNA into a host cell.} \\\\ 6. \\text{Screening/Selection:} \\text{Identification of successful transformants using marker genes (e.g., antibiotic resistance).} \\\\ 7. \\text{Expression:} \\text{Culturing the host to produce the desired protein product.} \\\\ \\text{Applications:} \\text{Production of recombinant human insulin, development of hepatitis B vaccines, creation of herbicide-resistant crops, and genetic disease diagnosis.}','The recombinant DNA technology cycle involves isolation, fragmentation, ligation, transformation, and expression, widely utilized in pharmaceutical production and agricultural biotechnology.','["Genetic Engineering", "Recombinant DNA Technology"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('1b4341303d6340464d3aff9becb4337221862e7d8d4ebaa5dcda50d3fbe192a4','Mid Semester','Unknown Subject (BE24101)','BE24101','4','2025','Q.5(b)','If the total number of seed obtained after a monohybrid cross between a Tall (TT) and dwarf (tt) plants is 100. Find the possible number of tall plant and dwarf plants. The punnett square for the monohybrid cross is given below. \'T\' stands for tall plant and \'t\' stands for dwarf plant.','\\text{If the total number of seed obtained after a monohybrid cross between a Tall (TT) and dwarf (tt) plants is 100. Find the possible number of tall plant and dwarf plants. The punnett square for the monohybrid cross is given below. \'T\' stands for tall plant and \'t\' stands for dwarf plant.}','1. Identification: Parent 1 is homozygous tall (TT) and Parent 2 is homozygous dwarf (tt). Total F1 seeds = 100. Find the number of tall and dwarf plants.\n2. Formula: A cross between TT and tt results in all F1 offspring having the genotype Tt. According to Mendelian dominance, T (tall) is dominant over t (dwarf). Therefore, all offspring with the Tt genotype exhibit the tall phenotype.\n3. Calculation: Since 100% of the F1 generation (100 seeds) will be Tt, all 100 plants will be phenotypically tall, and 0 plants will be phenotypically dwarf.\n4. Final Answer: 100 tall plants and 0 dwarf plants.','\\text{Step 1: Identify parents: } P_1 = TT, P_2 = tt. \\text{ F}_1 \\text{ genotype from } TT \\times tt \\text{ is } Tt. \\text{ Step 2: Determine phenotype: Since \'T\' is dominant, all } Tt \\text{ plants are Tall.} \\text{ Step 3: Calculate totals: } N_{\\text{tall}} = 100 \\times 1 = 100; N_{\\text{dwarf}} = 100 \\times 0 = 0.','100 tall plants, 0 dwarf plants','["Mendelian Genetics", "Monohybrid Cross"]','numerical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('2ae545444a93f67ae83d465fb763bf48b5c5914d12e43e0134b3246ce56f02e2','End Semester','Unknown Subject (BE24101)','BE24101','1','2025','Q.1(a)','Provide a schematic diagram of a typical fluid mosaic model of a cell membrane.','\\text{Provide a schematic diagram of a typical fluid mosaic model of a cell membrane.}','To describe the fluid mosaic model of the cell membrane, one must identify its primary components arranged in a bilayer structure. Step 1: Phospholipid Bilayer - The membrane consists of two layers of phospholipids with hydrophilic heads facing the aqueous environment and hydrophobic fatty acid tails facing inward. Step 2: Integral Proteins - These proteins span the membrane, functioning as channels or transporters. Step 3: Peripheral Proteins - These are attached to the surface of the bilayer. Step 4: Cholesterol - Distributed within the bilayer to regulate membrane fluidity. Step 5: Carbohydrate chains - Attached to proteins (glycoproteins) or lipids (glycolipids) on the extracellular side for cell recognition.','The fluid mosaic model consists of several key components organized into a bilayer structure: 1. Phospholipid Bilayer: The fundamental matrix where amphipathic phospholipids arrange their polar heads outward and non-polar tails inward. 2. Integral Proteins: Transmembrane proteins spanning the bilayer. 3. Peripheral Proteins: Proteins bound loosely to the membrane surface. 4. Cholesterol: Steroid molecules intercalated between phospholipids to stabilize membrane fluidity. 5. Carbohydrate moieties: Glycoproteins and glycolipids located on the extracellular face, facilitating cell-cell signaling.','A phospholipid bilayer matrix embedded with integral and peripheral proteins, cholesterol, and carbohydrate side chains.','["Cell Membrane", "Fluid Mosaic Model"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('bd7d707a5aa4902ca8ba2c928253341d5b6270e40475353a57a552dc4ca87a0e','End Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.1(b)','Define biotechnology and mention any two areas where it intersects with engineering','\\text{Define biotechnology and mention any two areas where it intersects with engineering}','Step 1: Define biotechnology. Biotechnology is a multidisciplinary field that utilizes biological systems, living organisms, or their derivatives to develop or modify products and processes for specific uses. Step 2: Identify two areas of intersection with engineering. Chemical engineering principles are applied in bioprocess engineering for the design of bioreactors, while genetic engineering applies mechanical and electrical engineering concepts (like systems control and modular design) to manipulate biological organisms for technological advancement.','\\text{Step 1: Biotechnology is defined as the application of biological systems, living organisms, or derivatives thereof, to make or modify products or processes for specific use. Step 2: Two key areas of intersection with engineering are: (1) Bioprocess Engineering, which applies transport phenomena and reaction kinetics to industrial-scale biological production; (2) Genetic Engineering, which utilizes systematic, iterative design principles to engineer DNA sequences and cellular pathways.}','Biotechnology is the use of biological systems to develop products. Intersections: 1. Bioprocess Engineering, 2. Genetic Engineering.','["Bioengineering", "Biotechnology"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b840e950c023e04882c9786e09da47f847857bfccf7b9d294bce20db1d1a8157','End Semester','Unknown Subject (BE24101)','BE24101','4','2025','Q.2(a)','Differentiate between DNA and RNA based on structure, function, and types','\\text{Differentiate between DNA and RNA based on structure, function, and types}','1. Structure: DNA is typically double-stranded, forming a double helix with deoxyribose sugar and bases Adenine, Guanine, Cytosine, and Thymine. RNA is typically single-stranded, containing ribose sugar and bases Adenine, Guanine, Cytosine, and Uracil. 2. Function: DNA acts as the permanent storage of genetic information in the cell. RNA is primarily involved in protein synthesis, including the transcription of genetic code and translation into amino acid sequences. 3. Types: DNA exists mainly as nuclear, mitochondrial, or chloroplast DNA. RNA exists in three primary types: messenger RNA (mRNA), transfer RNA (tRNA), and ribosomal RNA (rRNA).','\\begin{array}{|l|l|l|} \\hline \\textbf{Feature} & \\textbf{DNA} & \\textbf{RNA} \\\\ \\hline \\text{Structure} & \\text{Double-stranded, double helix} & \\text{Single-stranded} \\\\ \\hline \\text{Sugar} & \\text{Deoxyribose} & \\text{Ribose} \\\\ \\hline \\text{Nitrogenous Bases} & \\text{A, G, C, T} & \\text{A, G, C, U} \\\\ \\hline \\text{Function} & \\text{Long-term genetic storage} & \\text{Protein synthesis (transcription/translation)} \\\\ \\hline \\text{Types} & \\text{Nuclear, Mitochondrial, Chloroplast} & \\text{mRNA, tRNA, rRNA} \\\\ \\hline \\end{array}','DNA: Double-stranded, deoxyribose, A-G-C-T, genetic storage. RNA: Single-stranded, ribose, A-G-C-U, protein synthesis.','["DNA", "Nucleic Acids", "Programming Concepts", "RNA"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3b25bf68144f6067eee6eb9a6cd94906dccf9884ad7f823409220830a912ad47','End Semester','Unknown Subject (BE24101)','BE24101','2','2025','Q.2(b)','Discuss the functions of Carbohydrates and proteins.','\\text{Discuss the functions of Carbohydrates and proteins.}','1. Functions of Carbohydrates: Carbohydrates serve as the primary source of metabolic energy, providing 4 kcal/g through the process of cellular respiration (glycolysis and the citric acid cycle). They function as structural components, such as cellulose in plant cell walls or chitin in arthropod exoskeletons. Furthermore, they are critical for molecular recognition, acting as markers on cell membranes (glycoproteins and glycolipids), and serve as short-term energy storage in the form of glycogen in animals or starch in plants. 2. Functions of Proteins: Proteins are multifaceted macromolecules. They act as biological catalysts (enzymes) that lower activation energy for metabolic reactions. They provide structural support (collagen, keratin) and facilitate movement through contractile proteins (actin, myosin). Proteins function in molecular transport (hemoglobin), cell signaling (hormones like insulin), and immune defense (antibodies). Finally, they maintain osmotic balance and pH regulation within biological fluids.','\\text{1. Functions of Carbohydrates: (a) Energy Source: Primary fuel for cellular processes, yielding 4 kcal/g through oxidation. (b) Structural Support: Components like cellulose (plant cell walls) and chitin (fungi/arthropods). (c) Cell Recognition: Glycoconjugates on membranes mediate cell-cell communication. (d) Storage: Glycogen (animals) and starch (plants). 2. Functions of Proteins: (a) Catalysis: Enzymes accelerate biochemical reactions. (b) Structural: Collagen and keratin provide tissue integrity. (c) Movement: Contractile filaments (actin/myosin) enable muscular contraction. (d) Transport: Hemoglobin carries O2; membrane channels facilitate ion passage. (e) Signaling/Defense: Hormones and antibodies regulate physiological states and immunity.}','Carbohydrates provide energy, structure, and recognition; Proteins facilitate catalysis, structure, transport, signaling, and defense.','["Biomolecules", "Carbohydrates", "Programming Concepts", "Proteins"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('918baa1bcb6a225fb83657834748d4bab6467133099e06063b83e7c9022e9e5f','End Semester','Unknown Subject (BE24101)','BE24101','1','2025','Q.3(a)','Define cell signalling. Describe signal transduction and components involved in it.','\\text{Define cell signalling. Describe signal transduction and components involved in it.}','Cell signalling is the complex process by which cells communicate with their environment and each other using chemical or physical signals to coordinate physiological responses. Signal transduction is the biochemical process of converting an extracellular signal into a specific intracellular response. The key components include: 1. Signalling molecules (ligands) such as hormones or neurotransmitters. 2. Receptors (e.g., GPCRs, RTKs) located on the cell membrane or within the cytoplasm that detect the ligand. 3. Transducer proteins and second messengers (e.g., cAMP, Ca2+, IP3) that propagate and amplify the signal inside the cell. 4. Effector proteins (enzymes or transcription factors) that execute the final physiological change.','\\text{1. Definition: Cell signalling is a mechanism by which cells receive, process, and respond to environmental stimuli to maintain homeostasis and regulate development.}\\newline\\text{2. Signal Transduction: The process by which an extracellular signal is converted into a functional cellular response.}\\newline\\text{3. Key Components:}\\newline\\text{- Ligand: The primary signalling molecule (e.g., hormone, growth factor).}\\newline\\text{- Receptor: A protein that binds the ligand with high specificity, initiating a conformational change.}\\newline\\text{- Second Messengers: Small molecules like } cAMP, \\text{ cGMP, or } Ca^{2+} \\text{ that diffuse rapidly to relay the signal.}\\newline\\text{- Signalling Proteins: Kinases or phosphatases that propagate signals via phosphorylation cascades.}\\newline\\text{- Effectors: Target proteins (e.g., metabolic enzymes, transcription factors) that alter cellular behavior.}','Cell signalling is the process of cell-to-cell communication. Signal transduction is the conversion of an external stimulus into a cellular response via a sequence of receptors, second messengers, and effector proteins.','["Cell Signalling", "Signal Transduction"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('68b00753986fff2fed053c460b7a8b4a73956173e7e23a3ee2ce0e478b3fb9f3','End Semester','Unknown Subject (BE24101)','BE24101','2','2025','Q.3(b)','Explain how changes in environmental conditions such as temperature and pH can affect the activity of a specific enzyme used in an industrial or biological process. Discuss all such environmental factors.','\\text{Explain how changes in environmental conditions such as temperature and pH can affect the activity of a specific enzyme used in an industrial or biological process. Discuss all such environmental factors.}','1. Conceptual Analysis: Enzymes are protein catalysts that lower activation energy. Their activity depends on a specific tertiary structure (conformation) maintained by intramolecular bonds (hydrogen, ionic, disulfide). Changes in environment disrupt these interactions, leading to denaturation or loss of affinity.\n\n2. Factor 1 - Temperature: Increasing temperature increases kinetic energy, raising collision frequency until the optimum temperature is reached. Beyond this, thermal agitation breaks weak bonds, denaturing the enzyme. 3. Factor 2 - pH: pH affects the ionization states of amino acid side chains in the active site. Deviations from optimum pH disrupt ionic bonds, altering the charge distribution and preventing substrate binding. 4. Factor 3 - Substrate/Inhibitor Concentration: While not \'environmental\' in the strict sense, these define the chemical milieu. High substrate concentration leads to Vmax saturation; inhibitors compete for or modify the active site.\n\n5. Interpretation: Enzyme activity is a function of structural integrity. Deviations from physiological or industrial optimal ranges result in a decline in catalytic rate due to loss of the precise active site geometry.','1. \\text{Temperature Effects: } v = A e^{-E_a/RT}. \\text{As } T \\text{ increases, rate increases until } T_{opt} \\text{. Beyond } T_{opt}, \\text{ denaturation occurs as } \\Delta G_{unfolding} \\text{ becomes negative due to entropy-driven breakage of non-covalent interactions.} \\\\ 2. \\text{pH Effects: The ionization state of active site residues is governed by the Henderson-Hasselbalch equation: } pH = pK_a + \\log_{10}([A^-]/[HA]). \\text{ Deviations shift equilibrium, causing loss of catalytic protons/nucleophiles.} \\\\ 3. \\text{Industrial Impact: } k_{cat} \\text{ is maximized at } (T_{opt}, pH_{opt}). \\text{ Activity } \\mathcal{A} \\text{ is proportional to the fraction of folded native protein } [E_{native}]/[E_{total}].','Enzyme activity is optimized within narrow ranges of temperature and pH; deviations trigger structural denaturation or electrostatic inhibition, reducing catalytic efficiency.','["Enzyme Activity", "Enzymes", "Factors Affecting Enzymes"]','analytical','0.98',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('f1b3796572eacb5930b20fab30fd322bcc92fd0f9e8053d980be6178046ed041','End Semester','Unknown Subject (BE24101)','BE24101','4','2025','Q.4(a)','Explain why DNA has a single major function whereas proteins have diverse functions.','\\text{Explain why DNA has a single major function whereas proteins have diverse functions.}','1. Conceptual Analysis: The difference arises from the chemical structure and molecular stability of DNA versus proteins. DNA is optimized for stable, long-term information storage, while proteins are optimized for structural and catalytic versatility. 2. DNA Analysis: DNA consists of a deoxyribose-phosphate backbone and four bases (A, T, C, G). Its double-helical structure is rigid and chemically uniform, protecting the genetic code from degradation. This stability makes it an ideal \'library\' but limits its ability to participate in complex chemical reactions. 3. Protein Analysis: Proteins consist of 20 distinct amino acids with unique side chains (R-groups) that vary in charge, polarity, and size. These allow proteins to fold into intricate 3D shapes (conformations) and provide specific chemical microenvironments for catalysis, signaling, or mechanical support. 4. Interpretation: DNA is the \'blueprint\' (static storage) while proteins are the \'machinery\' (dynamic executors). The limited chemical diversity of DNA nucleotides favors storage fidelity, whereas the high chemical diversity of amino acids enables functional complexity.','\\text{1. DNA structure: Uniform phosphodiester backbone and four bases (A, T, C, G) facilitate base-pairing, stabilizing the double helix for information preservation.}\\newline \\text{2. Protein structure: Composed of 20 amino acids with unique R-groups (R}_i\\text{), allowing for complex tertiary folding governed by } \\Delta G = \\Delta H - T\\Delta S \\text{ considerations.}\\newline \\text{3. Functional implication: } \\text{Functionality } \\propto \\text{Chemical Diversity of Monomers. DNA (low diversity) } \\to \\text{storage. Protein (high diversity) } \\to \\text{catalysis, signaling, structure.}','DNA\'s uniform double-helical structure favors stable information storage, while the chemical diversity of 20 amino acids allows proteins to form complex 3D structures capable of diverse catalytic and structural roles.','["DNA Function", "Programming Concepts", "Protein Function"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('07ff85792a4182e73bfeb5313abf8dc66593d63dc75a663f22e09d49fc93a229','End Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.4(b)','Describe different types of biomaterials and discuss their applications.','\\text{Describe different types of biomaterials and discuss their applications.}','Biomaterials are classified based on their material composition and chemical structure. 1. Metals (e.g., Titanium, Stainless Steel, CoCr alloys) provide high mechanical strength and are used in load-bearing implants like hip replacements and dental anchors. 2. Ceramics (e.g., Alumina, Zirconia, Hydroxyapatite) offer excellent biocompatibility and wear resistance, often used in bone grafts and joint resurfacing. 3. Polymers (e.g., PE, PMMA, PLA, PGA) exhibit versatility; natural polymers (collagen, chitosan) offer high bioactivity, while synthetic polymers can be engineered for drug delivery systems and absorbable sutures. 4. Composites (e.g., carbon-fiber-reinforced polymers) combine properties of different materials to achieve specific mechanical requirements, such as enhanced toughness in structural implants.','\\text{Biomaterials are classified into four main categories: } \\\\ \\text{1. Metals: High mechanical strength, fatigue resistance. Applications: Orthopedic prostheses, dental implants, stents.} \\\\ \\text{2. Ceramics: High wear resistance, biocompatibility, brittleness. Applications: Bone repair, dental coatings, hip liners.} \\\\ \\text{3. Polymers: Tunable degradation rates, lightweight. Applications: Drug delivery systems, sutures, scaffolds for tissue engineering.} \\\\ \\text{4. Composites: Synergistic properties to overcome individual limitations. Applications: Bone cements, structural reinforcements in orthopedics.}','Biomaterials are classified into Metals, Ceramics, Polymers, and Composites, each serving specialized roles in clinical medicine ranging from structural support to functional drug delivery and tissue regeneration.','["Biomaterials"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3da1c8a37131e229ccb52b43dd9a70959a0ebef3b63777759fd04f11e273290f','End Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.5(a)','Discuss key ethical principles in Biological Science and Biotechnology.','\\text{Discuss key ethical principles in Biological Science and Biotechnology.}','Ethical principles in biological science and biotechnology are guided by the Belmont Report framework and the Nuremberg Code. 1. Respect for Persons: This principle mandates that individuals be treated as autonomous agents and that persons with diminished autonomy (e.g., children, prisoners) are entitled to protection. In practice, this requires informed consent. 2. Beneficence: Researchers must maximize possible benefits and minimize possible harms. This involves rigorous risk-benefit analysis and the ethical duty to protect the well-being of subjects. 3. Justice: This principle requires fairness in distribution, ensuring that the burdens and benefits of research are shared equitably and that vulnerable populations are not exploited. 4. Non-maleficence: The fundamental \'do no harm\' obligation, which in biotechnology extends to environmental safety and the long-term impacts of genetic modification. 5. Stewardship/Integrity: Emphasizes the responsible management of biological resources and the duty to maintain transparency and honesty in scientific reporting.','\\text{The ethical framework for Biological Science and Biotechnology is primarily defined by the following principles: } \\\\ 1. \\text{Respect for Persons: Autonomy and the requirement of informed consent.} \\\\ 2. \\text{Beneficence: The obligation to maximize benefits and minimize harm to research participants and society.} \\\\ 3. \\text{Justice: Fair distribution of the burdens and benefits of research, preventing exploitation of vulnerable groups.} \\\\ 4. \\text{Non-maleficence: The commitment to \'do no harm,\' including ecological impact assessment in biotechnology.} \\\\ 5. \\text{Scientific Integrity: Accountability, transparency, and ethical conduct in data management and dissemination.}','The core ethical framework consists of Respect for Persons, Beneficence, Justice, Non-maleficence, and Scientific Integrity.','["Bioethics"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('66850eb0d0310a2ed82e77a6d35e2b39b6df75c52447c0fe00f530d2f5892391','End Semester','Unknown Subject (BE24101)','BE24101','5','2025','Q.5(b)','Describe biosafety issues in Biotechnology and list the four biosafety levels.','\\text{Describe biosafety issues in Biotechnology and list the four biosafety levels.}','Biosafety issues in biotechnology involve the management of risks associated with the handling of biological agents to prevent accidental release or exposure. Key issues include: 1. Environmental risks, such as the horizontal gene transfer of modified organisms or the unintended disruption of ecosystems. 2. Occupational safety, which focuses on protecting laboratory personnel from pathogenic or toxic biological materials. 3. Ethical and security concerns, including the potential for misuse of synthetic biology (dual-use research). The four biosafety levels (BSL) are classified by the risk associated with the agents: BSL-1: Minimal risk; well-characterized agents not known to cause disease in healthy adults. BSL-2: Moderate risk; agents associated with human disease of varying severity. BSL-3: High risk; indigenous or exotic agents that may cause serious or lethal disease through inhalation. BSL-4: Extreme risk; dangerous/exotic agents that pose a high risk of aerosol-transmitted life-threatening disease for which there is often no vaccine or therapy.','\\text{Biosafety issues include: (1) Environmental impact: Potential for ecological imbalance due to the accidental release of GMOs. (2) Occupational safety: Risk of infection or exposure for laboratory staff. (3) Dual-use concerns: Potential exploitation of biological research for harmful purposes. The four Biosafety Levels (BSL) are: \\\\ BSL-1: Agents not known to consistently cause disease in healthy adults. \\\\ BSL-2: Agents associated with moderate hazards to personnel and the environment. \\\\ BSL-3: Agents that may cause serious or potentially lethal disease through the inhalation route. \\\\ BSL-4: Dangerous and exotic agents that pose a high individual risk of life-threatening disease.}','Biosafety issues: environmental risk, occupational safety, and dual-use concerns. Biosafety levels: BSL-1, BSL-2, BSL-3, and BSL-4.','["Biosafety", "Biosafety Levels"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('cb5ee3c93a6b6120fac65a41f0b7b73166e99d2569bb5c1bb376b8b18b86a663','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.1(a)','Write the characteristic features of living organisms.','\\text{Write the characteristic features of living organisms.}','Living organisms are distinguished from non-living matter by several fundamental biological criteria. 1. Cellular Organization: All living things are composed of one or more cells. 2. Metabolism: The sum total of all biochemical reactions occurring within an organism, including anabolism and catabolism, to maintain life. 3. Homeostasis: The ability to maintain a stable internal environment despite external fluctuations. 4. Growth and Development: The increase in size or complexity over time. 5. Reproduction: The ability to produce offspring, ensuring the continuation of the species. 6. Response to Stimuli: The capacity to sense and react to environmental changes. 7. Evolution and Adaptation: The ability of populations to undergo genetic changes over generations to better survive in their environment.','\\text{The characteristic features of living organisms are: } \\\\ 1. \\text{ Cellular Organization: Presence of one or more cells.} \\\\ 2. \\text{ Metabolism: Energy transformation through catabolic and anabolic pathways.} \\\\ 3. \\text{ Homeostasis: Maintenance of stable internal conditions.} \\\\ 4. \\text{ Growth and Development: Irreversible increase in size or complexity.} \\\\ 5. \\text{ Reproduction: Capability to produce viable offspring.} \\\\ 6. \\text{ Response to Stimuli: Sensitivity and reaction to environmental changes.} \\\\ 7. \\text{ Evolution: Genetic adaptation of populations over time.}','Cellular organization, Metabolism, Homeostasis, Growth, Reproduction, Response to stimuli, and Evolution.','["Characteristics of Life", "Living Organisms"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a2777faf153b90c26216dcb565950999eead938f88f01c5f837280a2756248f3','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.1(b)','Give a brief illustration on any two theories of origin of life','\\text{Give a brief illustration on any two theories of origin of life}','1. Theory of Spontaneous Generation (Abiogenesis): This ancient theory suggested that living organisms could arise spontaneously from non-living matter. For example, it was believed that decaying meat could give rise to maggots. This was later disproven by experiments conducted by Francesco Redi and Louis Pasteur, which demonstrated that life arises only from pre-existing life (Biogenesis). 2. Oparin-Haldane Theory (Chemical Evolution): This theory posits that life originated from non-living organic compounds through a series of chemical reactions in the early Earth\'s atmosphere. The primitive atmosphere, rich in methane, ammonia, hydrogen, and water vapor, provided the conditions for these molecules to synthesize into complex organic monomers (like amino acids and nucleotides) when exposed to energy sources like lightning and UV radiation. These molecules eventually aggregated to form the first simple life forms in the \'primordial soup\'.','\\text{1. Theory of Spontaneous Generation (Abiogenesis): This theory proposed that living organisms originated spontaneously from non-living matter. It was later falsified by Louis Pasteur, who demonstrated that life arises only from pre-existing life (Biogenesis).} \\\\ \\text{2. Oparin-Haldane Theory (Chemical Evolution): This theory suggests that life emerged from non-living chemical precursors in the early Earth\'s atmosphere. Under reducing conditions (CH}_4, \\text{NH}_3, \\text{H}_2, \\text{H}_2\\text{O}), energy from lightning and UV light catalyzed the synthesis of organic monomers, leading to the formation of complex molecules in a \'primordial soup\' where the first life forms developed.}','Theory of Spontaneous Generation and Oparin-Haldane Theory','["Evolutionary Theories", "Origin of Life"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('055a91a54520d7bb1581010fbf912a58f53e7d1af4b97a342a1ad1d65c6a4f6d','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.2(a)','Why is biology important for engineers?','\\text{Why is biology important for engineers?}','Biology is important for engineers because it provides a foundation for biomimicry, where natural designs inspire technological solutions. It enables the development of medical devices and prosthetics through an understanding of human physiology. Furthermore, biological systems function as complex chemical reactors, allowing for applications in biotechnology, synthetic biology, and environmental engineering for sustainable material synthesis and waste treatment.','1. \\text{Biomimicry: Studying biological structures allows engineers to innovate by replicating efficient natural designs.} \\\\ 2. \\text{Biomedical Engineering: Understanding human physiology is essential for the design of implants, imaging systems, and drug delivery mechanisms.} \\\\ 3. \\text{Biotechnology and Sustainability: Applying biological processes enables the creation of sustainable materials and efficient waste management systems through the manipulation of metabolic pathways.}','Biology facilitates innovation in design, medicine, and sustainable technology through biomimicry and biotechnology.','["Biology for Engineers"]','conceptual','0.98',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('0868dc4c533f8552ac2121f2edd248d94a9b6fa0a2f5b0d220699745c1720b13','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.2(b)','How will you differentiate between Plant and Animal cells? Explain with their contrasting features.','\\text{How will you differentiate between Plant and Animal cells? Explain with their contrasting features.}','Plant and animal cells are both eukaryotic but differ significantly in structure and function due to their distinct modes of nutrition and support requirements. The primary differences involve the presence of a rigid cell wall, large central vacuoles, and chloroplasts in plant cells, which are absent in animal cells. Conversely, animal cells contain centrosomes and centrioles for mitosis and may have smaller, temporary vacuoles. Plant cells are typically rectangular due to the cell wall, while animal cells are irregular or round.','\\text{The differentiation is based on the following features: } \\\\ 1. \\text{ Cell Wall: Present in plant cells (cellulose), absent in animal cells.} \\\\ 2. \\text{ Chloroplasts: Present in plant cells for photosynthesis, absent in animal cells.} \\\\ 3. \\text{ Vacuoles: Plant cells have a large central vacuole; animal cells have small, scattered, or no vacuoles.} \\\\ 4. \\text{ Centrioles: Absent in most higher plant cells, present in animal cells.} \\\\ 5. \\text{ Shape: Plant cells are fixed/rectangular; animal cells are irregular/flexible.} \\\\ 6. \\text{ Storage: Plants store energy as starch; animals store energy as glycogen.}','Plant cells contain cell walls, chloroplasts, and large central vacuoles; Animal cells lack these but possess centrioles and store glycogen.','["Animal Cells", "Cell Structure", "Plant Cells"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('9f5ea51a50e900e61593326a0a49b5c4e28577a9f3a68d39d6d98f79f0a46fca','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.3(a)','What is a cell? How does the cell theory establish the importance of cell?','\\text{What is a cell? How does the cell theory establish the importance of cell?}','1. Definition of a cell: A cell is defined as the fundamental structural, functional, and biological unit of all living organisms. It is the smallest entity capable of performing all life processes such as metabolism, homeostasis, and reproduction. 2. Role of Cell Theory: The cell theory posits three main tenets: (a) All living organisms are composed of one or more cells. (b) The cell is the basic unit of structure and organization in organisms. (c) Cells arise from pre-existing cells through division. 3. Importance: By establishing these principles, cell theory confirms that the continuity of life relies on cellular integrity. It provides a unified framework for biology, emphasizing that the properties of complex organisms are ultimately derived from the activities and interactions of their constituent cells.','\\text{1. Definition: A cell is the fundamental unit of life, serving as the basic structural, functional, and biological component of all living organisms. } \\\\ \\text{2. Cell Theory Tenets: } \\\\ \\text{(a) All living beings consist of one or more cells.} \\\\ \\text{(b) The cell is the basic unit of life.} \\\\ \\text{(c) Cells originate from pre-existing cells via division.} \\\\ \\text{3. Significance: Cell theory establishes that all life processes are cellular, implying that biological complexity, heredity, and metabolism are governed by cellular mechanisms, thereby defining the cell as the essential focal point of life science.}','A cell is the fundamental unit of life; the cell theory establishes its importance by identifying it as the universal structural, functional, and reproductive basis of all living organisms.','["Cell Biology", "Cell Theory"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('da2ac3fb389fdd4750bcaa6cbde35609aad8e8f5dcba3f14f0d546ab3b4e0fcc','Mid Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.3(b)','How can genome editing be useful in solving real world problem?','\\text{How can genome editing be useful in solving real world problem?}','1. Conceptual Analysis: Genome editing, primarily through CRISPR-Cas9, enables precise alterations to DNA sequences. This technology addresses real-world challenges by modifying the genetic architecture of organisms to enhance survival, productivity, or therapeutic outcomes. 2. Working: (a) Medicine: Genome editing allows for the correction of monogenic disorders like sickle cell anemia by modifying hematopoietic stem cells. (b) Agriculture: It enables the development of crops with enhanced nutritional profiles, resistance to pathogens, and tolerance to climate-induced stressors (e.g., drought). (c) Biocontrol: Strategies such as gene drives can be employed to alter populations of disease vectors (e.g., mosquitoes) to inhibit the transmission of malaria or dengue. 3. Interpretation: The utility of genome editing lies in its ability to intervene at the foundational biological level to provide scalable solutions for human health, global food security, and environmental stability.','\\text{1. Analysis: Genome editing (GE) modifies biological systems at the DNA level. The utility is measured by its capacity to solve } S \\text{ where } S = \\{H, A, E\\} \\text{ representing Health, Agriculture, and Environment.} \\\\ \\text{2. Applications:} \\\\ \\text{(a) Biomedical: Correcting pathological genotypes } g_{p} \\rightarrow g_{w} \\text{ (wild-type) for treating genetic diseases.} \\\\ \\text{(b) Agricultural: Enhancing phenotypic traits } P \\text{ through targeted mutagenesis to increase yield } Y \\text{ and resilience } R. \\\\ \\text{(c) Ecological: Utilizing gene-drive mechanisms } G \\text{ to manage disease-vector populations.} \\\\ \\text{3. Interpretation: GE shifts biology from observational to prescriptive, providing precise interventions to mitigate systemic issues in life sciences.}','Genome editing provides scalable solutions by correcting genetic diseases, enhancing agricultural resilience, and managing disease vectors, thereby addressing systemic issues in human health, food security, and ecology.','["Biotechnology Applications", "Genome Editing"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('2d0f5f6cf3f165fb3d58adb84ac913b758f066fdc0bdb532f5b3f0ffbac588f3','Mid Semester','Unknown Subject (BE24101)','BE24101','2','2024','Q.4(a)','Describe the basic structure of protein.','\\text{Describe the basic structure of protein.}','Protein structure is organized into four hierarchical levels: 1. Primary structure: The linear sequence of amino acids linked by covalent peptide bonds. 2. Secondary structure: Local folding patterns stabilized by hydrogen bonds between the polypeptide backbone, specifically alpha-helices and beta-pleated sheets. 3. Tertiary structure: The unique three-dimensional conformation of a single polypeptide chain, determined by interactions between R-groups (hydrophobic effects, disulfide bridges, ionic bonds, and hydrogen bonds). 4. Quaternary structure: The arrangement of multiple folded polypeptide subunits into a single functional complex.','\\text{The hierarchy of protein structure is defined as follows:} \\\\ 1. \\text{Primary: Linear sequence of amino acids linked by peptide bonds.} \\\\ 2. \\text{Secondary: Localized folding into } \\alpha \\text{-helices and } \\beta \\text{-sheets via backbone hydrogen bonding.} \\\\ 3. \\text{Tertiary: Global 3D conformation stabilized by R-group interactions (e.g., hydrophobic, disulfide, ionic).} \\\\ 4. \\text{Quaternary: Complex assembly of multiple polypeptide subunits.}','Primary, Secondary, Tertiary, and Quaternary levels.','["Protein Structure", "Proteins"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c134e23c63933467ddf5ae47c26d6a0339084106a869aff3beb3ec0d4495bbcc','Mid Semester','Unknown Subject (BE24101)','BE24101','4','2024','Q.4(b)','What is central dogma of molecular biology? Why it is important to understand?','\\text{What is central dogma of molecular biology? Why it is important to understand?}','1. Definition: The Central Dogma of molecular biology describes the flow of genetic information within a biological system, specifically stating that information flows from DNA to RNA (transcription) and then to protein (translation). 2. Components: It encompasses DNA replication (DNA to DNA), transcription (DNA to RNA), and translation (RNA to protein). 3. Importance: Understanding this concept is vital because it explains how genetic information encoded in nucleotides determines the structural and functional properties of organisms via proteins. It provides the foundation for genetics, molecular pathology, biotechnology, and personalized medicine by illustrating how mutations in DNA sequence can lead to functional changes in protein expression.','\\text{The Central Dogma states: } DNA \\xrightarrow{\\text{transcription}} RNA \\xrightarrow{\\text{translation}} Protein. \\text{ Importance: It defines the mechanism by which genetic information (genotype) dictates cellular phenotype. It is crucial for understanding: 1) Gene expression regulation, 2) The impact of genetic mutations, and 3) The development of therapeutic interventions targeting specific molecular pathways.}','The Central Dogma states that genetic information flows from DNA to RNA to Protein, serving as the fundamental framework for understanding biological inheritance and phenotypic expression.','["Central Dogma", "Molecular Biology"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('aba63f1af8dc060d5823cd7d2b2ced16b922621d967bf508cbec24a986870198','Mid Semester','Unknown Subject (BE24101)','BE24101','4','2024','Q.5(a)','What is DNA? Briefly describe its structure','\\text{What is DNA? Briefly describe its structure}','1. Definition: DNA, or Deoxyribonucleic acid, is the hereditary material in humans and almost all other organisms. It contains the instructions an organism needs to develop, live, and reproduce. 2. Structure: DNA consists of two long chains of nucleotides coiled into a double helix. Each nucleotide is composed of a sugar molecule (deoxyribose), a phosphate group, and one of four nitrogenous bases: Adenine (A), Thymine (T), Cytosine (C), or Guanine (G). The chains are held together by hydrogen bonds between complementary base pairs (A with T, and C with G).','\\text{1. Definition: DNA (Deoxyribonucleic acid) is the molecule that carries genetic information. 2. Structure: It forms a double-helical structure composed of two antiparallel polynucleotide strands. Each nucleotide contains a deoxyribose sugar, a phosphate group, and a nitrogenous base (A, T, C, or G). Complementary base pairing occurs via hydrogen bonding, specifically A=T and G\\equiv C.}','DNA is a double-helical molecule composed of two antiparallel strands of nucleotides (deoxyribose, phosphate, and nitrogenous bases A, T, C, G) held together by hydrogen bonds.','["DNA Structure"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4531f251d07e543c91734894bc20127c607c4ff1e36ffb38cee10c931bcf70b8','Mid Semester','Unknown Subject (BE24101)','BE24101','4','2024','Q.5(b)','Explain the law of segregation in Mendelian genetics.','\\text{Explain the law of segregation in Mendelian genetics.}','1. Definition: The law of segregation states that during the formation of gametes, the two alleles of a gene pair separate (segregate) from each other so that each gamete receives only one allele. 2. Mechanism: This occurs during Anaphase I of meiosis, where homologous chromosomes move to opposite poles of the cell. 3. Result: Each offspring inherits one allele from each parent, restoring the diploid state upon fertilization, ensuring that alleles remain distinct entities that do not blend.','\\text{1. Definition: The law of segregation states that during gamete formation, the two alleles at a gene locus segregate from each other, such that each gamete carries only one allele. 2. Meiotic Basis: This corresponds to the separation of homologous chromosomes during Anaphase I of meiosis. 3. Genetic Implication: If an individual has genotype } Aa \\text{, gametes will be produced in a 1:1 ratio of } A \\text{ and } a \\text{ alleles. 4. Conclusion: This ensures that the inheritance of one trait is independent of the other and that alleles do not blend, preserving genetic variation.}','Each gamete receives only one of the two parental alleles, ensuring Mendelian inheritance ratios.','["Law of Segregation", "Mendelian Genetics"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a45886a7c08945b2e719aecf170638e164fac0d9e02e438042c23422dc0fef1b','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.1(a)','Describe Miller\'s experiment with suitable diagram.','\\text{Describe Miller\'s experiment with suitable diagram.}','Miller\'s experiment (1953) simulated conditions of the primordial Earth to test Oparin-Haldane\'s theory of chemical evolution. 1. Apparatus Setup: A closed system of glass flasks and tubes. A large flask contained a mixture of water vapor (H2O), methane (CH4), ammonia (NH3), and hydrogen (H2) in a 2:2:1:2 ratio. 2. Simulation of Energy: Electric sparks were discharged across tungsten electrodes in the large flask to simulate lightning. 3. Condensation: A condenser cooled the vapor, mimicking rain, which collected the synthesized compounds into a smaller flask. 4. Results: After a week of operation, the water in the trap turned deep red, containing simple organic compounds like amino acids (e.g., glycine, alanine) and organic acids, demonstrating that abiotic synthesis of organic life building blocks is possible.','Miller-Urey experiment setup: \\begin{itemize} \\item \\textbf{Components:} A large flask (simulating atmosphere) connected to a small flask (simulating primordial ocean). \\item \\textbf{Atmosphere:} H_2O (vapor), CH_4, NH_3, and H_2 were introduced in a sterile closed-loop. \\item \\textbf{Energy Source:} Tungsten electrodes provided continuous electric discharges (simulating lightning). \\item \\textbf{Cycling:} Steam was condensed through a water-cooled condenser, allowing circulated water to dissolve synthesized products. \\item \\textbf{Analysis:} Chromatographic analysis of the collected liquid revealed amino acids such as glycine and alanine, confirming the abiotic synthesis of organic monomers from inorganic precursors. \\end{itemize}','The Miller-Urey experiment demonstrated the abiotic synthesis of organic monomers from inorganic precursors, providing empirical support for the chemical evolution of life.','["Miller-Urey Experiment", "Origin of Life"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e251c4ba53db67505429add446974eac17d9e01b0b94f751e8a6b42c62dbb91b','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.1(b)','Explain the structure and function of mitochondria and plasma membrane with suitable diagram.','\\text{Explain the structure and function of mitochondria and plasma membrane with suitable diagram.}','1. Mitochondria: Structure includes a double-membrane system with an outer membrane, an intermembrane space, and an inner membrane folded into cristae enclosing the matrix. Function: Acts as the powerhouse of the cell, primarily synthesizing ATP through aerobic respiration (Krebs cycle and electron transport chain). 2. Plasma Membrane: Structure follows the fluid mosaic model, consisting of a phospholipid bilayer embedded with integral and peripheral proteins, cholesterol, and carbohydrates. Function: Regulates the passage of substances in and out of the cell (selective permeability), provides structural support, and facilitates cell signaling and recognition.','\\text{1. Mitochondria: Structure comprises an outer membrane, intermembrane space, and highly folded inner membrane (cristae) surrounding the matrix. Function: ATP production via oxidative phosphorylation. 2. Plasma Membrane: Structure is a phospholipid bilayer with embedded proteins (Fluid Mosaic Model). Function: Selective permeability, compartmentalization, and signal transduction.}','Mitochondria produce ATP via respiration; Plasma membrane regulates molecular transport and provides structural integrity.','["Cell Structure", "Mitochondria", "Plasma Membrane", "Programming Concepts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c55c6e859cfd8feabe943ab44e2d2578f14e4981c349d889d08e09fafce3ed90','End Semester','Unknown Subject (BE24101)','BE24101','2','2024','Q.2(a)','What are protein made of and why they are important for cells?','\\text{What are protein made of and why they are important for cells?}','1. Composition: Proteins are biological polymers composed of long chains of amino acids linked together by peptide bonds. There are 20 standard amino acids, each characterized by a central alpha-carbon atom, an amino group, a carboxyl group, and a unique side chain (R-group) that determines the protein\'s specific chemical properties and 3D folding structure. 2. Importance: Proteins serve multiple critical functions in cells: (a) Structural support, providing mechanical integrity (e.g., cytoskeleton, collagen); (b) Enzymatic catalysis, accelerating biochemical reactions necessary for metabolism; (c) Cell signaling, acting as receptors and hormones to facilitate communication; (d) Transport, moving molecules across membranes (e.g., ion channels); and (e) Defense, acting as antibodies to protect against pathogens.','1. \\text{Composition: Proteins are polymers of amino acids linked via peptide bonds. The general structure of an amino acid is } H_2N-CH(R)-COOH, \\text{ where R represents one of the 20 distinct side chains.} \\\\ 2. \\text{Functional Importance: Proteins are essential to cellular life due to: } \\\\ (a) \\text{Catalysis: Enzymes lower activation energy for metabolic reactions.} \\\\ (b) \\text{Structure: Proteins like actin and tubulin maintain cell shape.} \\\\ (c) \\text{Transport: Membrane proteins regulate molecular traffic.} \\\\ (d) \\text{Signaling: Receptor proteins mediate cellular responses to environmental stimuli.}','Proteins are polymers of amino acids; they are vital for enzymatic catalysis, structural integrity, molecular transport, and cellular signaling.','["Cellular Importance", "Proteins"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('272429f74aecc2c3357fceb578430280045ede0f2d5604fc35008bcf42ec8b6e','End Semester','Unknown Subject (BE24101)','BE24101','3','2024','Q.3(a)','How glucose molecules are broken down into pyruvates? Give the metabolic steps involve in it.','\\text{How glucose molecules are broken down into pyruvates? Give the metabolic steps involve in it.}','The breakdown of glucose into pyruvate occurs via glycolysis in the cytoplasm. It proceeds in ten enzyme-catalyzed steps divided into two phases: 1. Preparatory Phase: Glucose is phosphorylated to glucose-6-phosphate by hexokinase, isomerized to fructose-6-phosphate, phosphorylated to fructose-1,6-bisphosphate by phosphofructokinase-1 (the rate-limiting step), cleaved into dihydroxyacetone phosphate and glyceraldehyde-3-phosphate (GAP) by aldolase, and the former is isomerized to GAP. 2. Payoff Phase: Each GAP is oxidized and phosphorylated to 1,3-bisphosphoglycerate, which then transfers a phosphate to ADP to form ATP and 3-phosphoglycerate, followed by isomerization to 2-phosphoglycerate, dehydration to phosphoenolpyruvate (PEP), and a final substrate-level phosphorylation by pyruvate kinase to yield pyruvate.','The metabolic pathway of glycolysis consists of the following ten steps: 1. \\text{Glucose} + \\text{ATP} \\xrightarrow{\\text{hexokinase}} \\text{Glucose-6-phosphate} + \\text{ADP}. 2. \\text{G6P} \\xleftrightarrow{\\text{phosphoglucose isomerase}} \\text{Fructose-6-phosphate}. 3. \\text{F6P} + \\text{ATP} \\xrightarrow{\\text{PFK-1}} \\text{Fructose-1,6-bisphosphate} + \\text{ADP}. 4. \\text{F1,6BP} \\xleftrightarrow{\\text{aldolase}} \\text{Dihydroxyacetone phosphate} + \\text{Glyceraldehyde-3-phosphate}. 5. \\text{DHAP} \\xleftrightarrow{\\text{triose phosphate isomerase}} \\text{Glyceraldehyde-3-phosphate}. 6. \\text{GAP} + \\text{NAD}^+ + \\text{Pi} \\xleftrightarrow{\\text{GAPDH}} \\text{1,3-bisphosphoglycerate} + \\text{NADH} + \\text{H}^+. 7. \\text{1,3-BPG} + \\text{ADP} \\xrightarrow{\\text{phosphoglycerate kinase}} \\text{3-phosphoglycerate} + \\text{ATP}. 8. \\text{3-PG} \\xleftrightarrow{\\text{phosphoglycerate mutase}} \\text{2-phosphoglycerate}. 9. \\text{2-PG} \\xleftrightarrow{\\text{enolase}} \\text{Phosphoenolpyruvate} + \\text{H}_2\\text{O}. 10. \\text{PEP} + \\text{ADP} \\xrightarrow{\\text{pyruvate kinase}} \\text{Pyruvate} + \\text{ATP}. \\text{Net Equation: } \\text{Glucose} + 2\\text{NAD}^+ + 2\\text{ADP} + 2\\text{Pi} \\rightarrow 2\\text{Pyruvate} + 2\\text{NADH} + 2\\text{ATP} + 2\\text{H}_2\\text{O} + 2\\text{H}^+.','\\text{Glucose} + 2\\text{NAD}^+ + 2\\text{ADP} + 2\\text{Pi} \\rightarrow 2\\text{Pyruvate} + 2\\text{NADH} + 2\\text{ATP} + 2\\text{H}_2\\text{O} + 2\\text{H}^+','["Glycolysis", "Metabolism"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('1d7ef74f2366f43db149af76b57114a2ede97e75fc295d5a4022cca4e77ad8f8','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.3(b)','Discuss the different types of cell signalling.','\\text{Discuss the different types of cell signalling.}','Cell signalling is the process by which cells communicate with each other to coordinate physiological functions. The primary types are categorized based on the distance the signal travels: 1. Endocrine signaling: Hormones are secreted into the bloodstream to act on distant target cells. 2. Paracrine signaling: Signaling molecules act on nearby target cells via local diffusion. 3. Autocrine signaling: A cell secretes a molecule that binds to receptors on its own surface. 4. Juxtacrine signaling: Requires direct physical contact between adjacent cells (e.g., via membrane-bound proteins). 5. Synaptic signaling: A specialized form of paracrine signaling where neurons release neurotransmitters across a synapse to a target cell.','\\text{Cell signalling is categorized by the distance of the signal transmission:} \\\\ 1. \\text{Endocrine: Hormones travel through the circulatory system to distant targets.} \\\\ 2. \\text{Paracrine: Local mediators affect cells in the immediate vicinity.} \\\\ 3. \\text{Autocrine: The cell responds to its own secreted ligands.} \\\\ 4. \\text{Juxtacrine: Direct contact between cells through surface-bound proteins.} \\\\ 5. \\text{Synaptic: Chemical neurotransmitters release at synapses to act on specific postsynaptic cells.}','Endocrine, Paracrine, Autocrine, Juxtacrine, and Synaptic signalling.','["Cell Signalling"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('78730794c7c84960ae8e589cb0a5da60a493f2522284bfaf216fca29762daf3b','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.4(a)','What are biomaterials? Describe the salient characteristics of biomaterials.','\\text{What are biomaterials? Describe the salient characteristics of biomaterials.}','Step 1: Define biomaterials. A biomaterial is any substance (natural or synthetic) engineered to interact with biological systems for a medical purpose, either to treat, augment, repair, or replace a tissue function of the body. Step 2: Identify salient characteristics. The key requirements include: 1. Biocompatibility: The ability to exist in harmony with the host tissue without causing an adverse immune response, inflammation, or toxicity. 2. Bioactivity/Bio-inertness: Depending on the application, the material should either integrate with host tissue (bioactive) or remain chemically unreactive (bio-inert). 3. Mechanical Integrity: The material must possess mechanical properties (strength, elasticity, fatigue resistance) that match the tissue it replaces. 4. Sterilizability: The ability to be sterilized without compromising the material\'s physical or chemical properties. 5. Biodegradability: In cases of temporary scaffolds, the material should degrade into non-toxic metabolites at a controlled rate.','\\text{1. Definition: A biomaterial is a substance that has been engineered to take a form which, alone or as part of a complex system, is used to direct, by control of interactions with components of living systems, the course of any therapeutic or diagnostic procedure.}\\newline \\text{2. Salient Characteristics:}\\newline \\bullet \\text{Biocompatibility: The material must not elicit an adverse host response.}\\newline \\bullet \\text{Mechanical Properties: The material must possess the necessary tensile, compressive, and fatigue strength to withstand physiological loading.}\\newline \\bullet \\text{Chemical Stability: Resistance to degradation by the body\'s aggressive chemical environment (or controlled degradation for scaffolds).}\\newline \\bullet \\text{Bio-interface properties: Surface energy and topography must promote desired cell adhesion or prevent fouling.}\\newline \\bullet \\text{Processability/Sterilizability: Must be manufacturable and capable of being sterilized without property loss.}','Biomaterials are engineered substances designed to interact with biological systems for medical purposes, characterized primarily by biocompatibility, mechanical suitability, chemical stability, and appropriate surface functionality.','["Biomaterials"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e5cf74b234f19fd11c68137c95a18b578fb89e42270229810cf09e5e3615c0f7','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.4(b)','What is bioinformatics? Describe different components of bioinformatics.','\\text{What is bioinformatics? Describe different components of bioinformatics.}','Bioinformatics is an interdisciplinary field that develops methods and software tools for understanding biological data, particularly when the datasets are large and complex. It integrates computer science, statistics, mathematics, and engineering to analyze and interpret biological information. The key components include: 1. Data acquisition and storage: Creating databases to manage vast genomic and proteomic data. 2. Data analysis tools: Developing algorithms for sequence alignment, gene finding, and structural prediction. 3. Interpretation and visualization: Tools to map molecular interactions and visualize biological pathways.','\\text{Bioinformatics is the application of computational tools and methods to manage, analyze, and interpret biological data, particularly at the molecular level. It functions through three primary components: (1) \\textbf{Database Management}: The storage and curation of biological data (e.g., GenBank, PDB) to ensure accessibility and standardization. (2) \\textbf{Algorithm Development}: The design of mathematical models for sequence alignment, phylogenetic analysis, and structure prediction. (3) \\textbf{Data Interpretation}: The use of statistical analysis and machine learning to infer biological functions, protein-protein interactions, and metabolic pathways from raw data.}','Bioinformatics is the computational intersection of biology and data science, consisting of data storage, algorithm development for sequence analysis, and functional data interpretation.','["Bioinformatics"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('318733f2e90324aec61c179d8dad07a1b76f6f196b8ae8d1b38729e6eb2ae12e','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.5(a)','Write a short note on application of Al in biology.','\\text{Write a short note on application of Al in biology.}','The application of Artificial Intelligence (AI) in biology involves using computational algorithms to analyze, predict, and interpret complex biological data. Key applications include: 1. Protein Structure Prediction: AI models like AlphaFold predict the 3D structure of proteins from amino acid sequences, solving a long-standing challenge in molecular biology. 2. Genomics and Precision Medicine: Machine learning algorithms analyze genetic sequences to identify disease-linked variants and suggest personalized treatment plans. 3. Drug Discovery: AI accelerates drug development by predicting the binding affinity between potential drug compounds and biological targets, significantly reducing experimental costs. 4. Medical Imaging: Computer vision techniques analyze histological or radiological images to automate the detection of abnormalities like tumors or cellular mutations. 5. Systems Biology: AI models simulate complex signaling pathways and metabolic networks to understand biological system behavior.','\\text{The application of AI in biology encompasses several critical domains:} \\\\ 1. \\text{Protein Folding: Predictive modeling of 3D protein structures from primary sequences (e.g., AlphaFold).} \\\\ 2. \\text{Genomics: Pattern recognition in DNA sequencing to identify mutations and predict phenotypic outcomes.} \\\\ 3. \\text{Drug Discovery: Virtual screening of molecular libraries to identify high-affinity ligands for therapeutic targets.} \\\\ 4. \\text{Medical Diagnostics: Utilizing convolutional neural networks (CNNs) for image-based classification of clinical samples.} \\\\ 5. \\text{Systems Biology: Integration of multi-omics data to model cellular dynamics and network interactions.}','AI in biology revolutionizes research via protein structure prediction, genomics, drug discovery, diagnostics, and systems modeling.','["AI in Biology", "Computational Biology"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('8a7f68b3ba6b7c83bb207c464fe5b2dfc401ad49c6a4ae2c293be4b85ec85e14','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.5(b)','Comment on impact of climate change on food security.','\\text{Comment on impact of climate change on food security.}','1. Conceptual Analysis: Climate change affects food security through four key dimensions: availability (production), access (distribution/economic), stability (frequency/severity of climate events), and utilization (nutritional quality/health). We must analyze the shift in agricultural productivity, supply chain disruption, and socioeconomic vulnerability. 2. Step-by-Step Derivation: Step 1: Analyze crop yield variability. Increased temperatures and altered precipitation patterns reduce yield potential for major staples like wheat and rice. Step 2: Analyze supply chain impacts. Extreme weather events (floods, droughts) damage infrastructure, leading to price volatility and reduced food access. Step 3: Analyze nutritional quality. Elevated atmospheric CO2 concentrations decrease the density of essential nutrients (e.g., zinc, iron, proteins) in key crops. 3. Interpretation: The cumulative effect is a decrease in global food security indices, disproportionately affecting vulnerable populations in low-latitude, agrarian-dependent regions.','\\text{Step 1: Yield Impact. Let } Y \\text{ represent agricultural yield. } Y = f(T, P, C), \\text{ where } T \\text{ is temperature, } P \\text{ is precipitation, and } C \\text{ is CO}_2 \\text{ concentration. As } T > T_{opt} \\text{ and } P \\text{ becomes erratic, } \\frac{\\partial Y}{\\partial T} < 0 \\text{ and } \\sigma^2_Y \\text{ increases.} \\newline \\text{Step 2: Nutritional Quality. } Q_{nut} \\propto \\frac{1}{C}. \\text{ Increased } C \\text{ leads to a decline in grain protein content, reducing caloric and nutrient intake efficiency.} \\newline \\text{Step 3: Stability. Food security } S = \\int (Availability \\cap Access \\cap Stability \\cap Utilization) dt. \\text{ Climate-induced shocks result in } \\Delta S < 0 \\text{ as frequency of extreme events increases.}','Climate change acts as a systemic stressor that destabilizes food systems by reducing crop yields, disrupting supply chains, and decreasing the nutritional density of staples, leading to a net reduction in global food security.','["Climate Change", "Food Security"]','analytical','0.95',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('dc99379e4015084ceadf9d5a135256a03147c571e6ecc93cd8d64ea14bfc680b','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.1(a)','Diagrammatically illustrate the structural and functional importance of mitochondria and nucleus of a cell.','\\text{Diagrammatically illustrate the structural and functional importance of mitochondria and nucleus of a cell.}','Step 1: Nucleus Structure and Function. The nucleus is bounded by a double membrane (nuclear envelope) with pores. It contains chromatin (DNA and proteins) and the nucleolus. Functionally, it serves as the genetic repository, controlling gene expression and mediating DNA replication and transcription. Step 2: Mitochondria Structure and Function. Mitochondria possess an outer membrane and a highly folded inner membrane (cristae) enclosing the matrix. Functionally, they are the site of aerobic respiration, generating ATP through the electron transport chain and oxidative phosphorylation. Step 3: Synthesis. The nucleus acts as the command center for protein synthesis instructions, while the mitochondria provide the energy required to execute these cellular processes.','\\text{Step 1: The nucleus consists of a nuclear envelope with pores, nucleoplasm, and chromatin. Function: It acts as the genetic control center, housing DNA for transcription and regulating cellular activities via mRNA export. Step 2: Mitochondria consist of an outer membrane, inner cristae, and a matrix containing enzymes and mtDNA. Function: They function as the powerhouse of the cell, converting biochemical energy from nutrients into adenosine triphosphate (ATP) via the Krebs cycle and oxidative phosphorylation. Step 3: Structural-Functional Integration: The nucleus dictates cellular trajectory through gene expression, while mitochondria supply the thermodynamic requirements for these biochemical pathways to proceed.}','The nucleus controls cellular activity via genetic regulation, and mitochondria sustain cellular life through ATP production.','["Cell Biology", "Mitochondria", "Nucleus", "Programming Concepts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('1229997b9c9a4fc8afc0f357b4b3f61072111deaabb298e8adf95d1494736caf','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.1(b)','Explain the steps in detail that occur during the mitosis cell division.','\\text{Explain the steps in detail that occur during the mitosis cell division.}','Mitosis is the process of nuclear division in eukaryotic cells, occurring in four primary stages: 1. Prophase: Chromatin condenses into visible chromosomes, the nuclear envelope breaks down, and the spindle apparatus forms. 2. Metaphase: Chromosomes align along the cell\'s equatorial plane, with spindle fibers attaching to the kinetochores. 3. Anaphase: Sister chromatids are pulled apart by spindle fibers toward opposite poles of the cell. 4. Telophase: A nuclear envelope reforms around each set of chromosomes, which begin to decondense. This is typically followed by cytokinesis, the physical division of the cytoplasm.','\\text{Mitosis occurs in four sequential stages: 1. Prophase: Chromatin condenses into chromosomes (2n), the nuclear envelope disintegrates, and the mitotic spindle forms. 2. Metaphase: Chromosomes align at the metaphase plate; kinetochore microtubules attach to sister chromatids. 3. Anaphase: Sister chromatids separate and move toward opposite poles via shortening of kinetochore microtubules. 4. Telophase: Chromosomes decondense, and nuclear envelopes reform around two distinct sets of genetic material.}','Prophase \\rightarrow Metaphase \\rightarrow Anaphase \\rightarrow Telophase','["Cell Division", "Mitosis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('f9550b7a10dea5f191fea76e946f64e243f034327af2f7b73dbeb531b0d4365e','End Semester','Unknown Subject (BE24101)','BE24101','3','2024','Q.2(b)','Sketch the photosynthesis pathway and evaluate the importance of photosynthesis towards enhancing the productivity and nourishing the overwhelming population.','\\text{Sketch the photosynthesis pathway and evaluate the importance of photosynthesis towards enhancing the productivity and nourishing the overwhelming population.}','The problem requires a conceptual sketch of photosynthesis and an evaluation of its role in food security. 1. Analysis: Photosynthesis is a two-stage process (light-dependent and light-independent reactions) converting solar energy into chemical energy (glucose) using water and carbon dioxide. 2. Working: The light-dependent reaction occurs in thylakoids, generating ATP and NADPH. The Calvin cycle occurs in the stroma, fixing CO2 into G3P. The productivity impact relates to primary biomass production, which forms the base of the global food web, supporting caloric needs for the global population. 3. Interpretation: Photosynthesis is the ultimate source of metabolic energy for heterotrophs and biomass for human sustenance, making it the fundamental driver of agricultural yield and planetary carrying capacity.','\\text{Step 1: Conceptual Framework. Photosynthesis: } 6CO_2 + 12H_2O + \\text{light} \\rightarrow C_6H_{12}O_6 + 6O_2 + 6H_2O. \\text{ Phase I: Light-dependent (thylakoid) producing ATP, NADPH, and } O_2. \\text{ Phase II: Calvin Cycle (stroma) converting } CO_2 \\text{ to sugars. Step 2: Evaluation. Productivity is defined by the rate of carbon fixation. As the foundation of the trophic pyramid, the efficiency of this pathway determines the Net Primary Productivity (NPP). By increasing photosynthetic efficiency (e.g., C4 vs C3 plants), we maximize yield per land area to nourish the growing population.}','Photosynthesis is the fundamental biological engine for global food production, converting solar energy into fixed carbon (biomass), which determines the primary caloric capacity of the biosphere to support human civilization.','["Photosynthesis", "Plant Productivity"]','analytical','0.95',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('631cc024fc598a8f0f36bcf94b468ba73f9bd834802cded9eef176573ca0288f','End Semester','Unknown Subject (BE24101)','BE24101','2','2024','Q.3(a)','Explain the detailed mechanism of enzyme action with suitable diagrams.','\\text{Explain the detailed mechanism of enzyme action with suitable diagrams.}','The mechanism of enzyme action is described primarily through two models: the Lock and Key hypothesis and the Induced Fit theory. 1. Enzyme-Substrate Binding: Enzymes possess an active site, a specific pocket complementary to the substrate. 2. Formation of ES Complex: The substrate binds to the active site, forming a transient Enzyme-Substrate (ES) complex. 3. Transition State: The enzyme lowers the activation energy by stabilizing the transition state, often via chemical strain or orientation effects. 4. Product Formation: The substrate is converted into product (EP complex). 5. Release: The products are released, and the enzyme returns to its original conformation, ready to catalyze another reaction. The Induced Fit model refines this by suggesting the active site undergoes conformational changes upon substrate binding to optimize catalytic efficiency.','The mechanism of enzyme catalysis is described by the reaction: E + S \\rightleftharpoons ES \\rightarrow EP \\rightleftharpoons E + P. Step 1: Binding. The substrate (S) binds to the active site of the enzyme (E) to form the ES complex. Step 2: Transition State Stabilization. The enzyme lowers the Gibbs free energy of activation (\\Delta G^{\\ddagger}) by providing an alternative pathway, often described by the Induced Fit model where the enzyme undergoes a conformational change to stabilize the transition state. Step 3: Product Formation. Chemical bonds are broken or formed, resulting in the EP complex. Step 4: Release. The product (P) is released, and the enzyme (E) is regenerated in its original state. The rate enhancement follows the Arrhenius equation, k = Ae^{-E_a/RT}, where the enzyme significantly reduces the activation energy E_a.','E + S \\rightleftharpoons ES \\rightarrow EP \\rightarrow E + P','["Enzyme Mechanism", "Enzymes"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('5387fcca16831eb72d5b0b7d45d8a4de1d1c34124e3095fefd8dfa3e1798aa96','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.3(b)','Discuss the various methods used for enzyme immobilization and its industrial importance.','\\text{Discuss the various methods used for enzyme immobilization and its industrial importance.}','Enzyme immobilization is the physical or chemical confinement of enzymes to a support matrix. The primary methods include: 1. Adsorption: Enzymes attach to the surface of a support via weak forces (e.g., Van der Waals). It is simple and preserves activity but is prone to leaching. 2. Covalent Binding: Strong chemical bonds form between enzyme functional groups (e.g., amine, carboxyl) and the support. This prevents leaching but may alter the active site. 3. Entrapment: Enzymes are caged within a polymer matrix (e.g., alginate beads) or semi-permeable membrane. This prevents leakage but may limit mass transfer. 4. Cross-linking: Enzymes are linked to each other using bifunctional agents (e.g., glutaraldehyde) to form insoluble aggregates. Industrial importance includes: enhanced stability against pH and temperature, ease of enzyme separation from the product stream, and the ability to reuse enzymes in continuous flow bioreactors, leading to significant cost reduction and process efficiency.','\\text{Enzyme immobilization techniques involve: } \\\\ 1. \\text{ Adsorption: Physical attachment to a support matrix via non-covalent interactions.} \\\\ 2. \\text{ Covalent binding: Chemical formation of stable bonds between enzyme and support.} \\\\ 3. \\text{ Entrapment: Physical restriction of the enzyme within a lattice or semi-permeable membrane.} \\\\ 4. \\text{ Cross-linking: Intermolecular linkages via cross-linking agents like glutaraldehyde.} \\\\ \\text{Industrial Importance: } \\\\ \\text{I. Stability: Enhanced resistance to environmental stressors (pH, heat).} \\\\ \\text{II. Recoverability: Easy separation from products allows for enzyme recycling.} \\\\ \\text{III. Economics: Enables continuous operation in bioreactors, reducing operational costs.}','Methods: Adsorption, Covalent Binding, Entrapment, Cross-linking. Importance: Enhanced stability, reusability, and continuous process feasibility.','["Enzyme Immobilization", "Industrial Biotechnology"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('40e9106616d65173a47bdb9d15e2f3deee949a8830619a98489443f1f890e319','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.4(a)','Diagrammatically describe the nerve cell structure as well as its role in signal propagation.','\\text{Diagrammatically describe the nerve cell structure as well as its role in signal propagation.}','A nerve cell (neuron) consists of a cell body (soma), dendrites, and an axon. Dendrites receive electrical signals from other neurons. The soma integrates these signals. The axon propagates the action potential away from the soma toward the synaptic terminals. The process involves: 1. Resting membrane potential (approximately -70 mV) maintained by Na+/K+ pumps. 2. Depolarization triggered by ion channels opening (Na+ influx) when a threshold is reached. 3. Repolarization (K+ efflux) restoring the resting potential. 4. Saltatory conduction, where the signal jumps between nodes of Ranvier in myelinated axons, increasing propagation speed.','The structure of a neuron is categorized into: (1) Dendrites: Input sites; (2) Soma (Cell body): Integration center; (3) Axon: Signal propagation pathway; (4) Myelin Sheath: Insulating layer accelerating transmission; (5) Synaptic Terminals: Output sites. The mechanism of propagation involves the action potential: V_m(t) = V_{rest} + \\Delta V_{threshold}. Upon threshold excitation, voltage-gated Na^+ channels open causing an influx, leading to depolarization. Subsequently, voltage-gated K^+ channels cause repolarization. The velocity v of the signal is governed by the cable equation: \\lambda^2 \\frac{\\partial^2 V}{\\partial x^2} = \\tau \\frac{\\partial V}{\\partial t} + V, where \\lambda is the length constant and \\tau is the time constant. In myelinated neurons, conduction is saltatory, occurring at the nodes of Ranvier, significantly increasing v.','Neurons propagate signals via action potentials generated by ion flux across the membrane, optimized by myelin insulation and saltatory conduction.','["Nerve Cell", "Neurons", "Signal Propagation"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('1f99f10539205dedb50ca5d50e047bf7b3e1227fc0d1fb82922c016f7d79e4e6','End Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.4(b)','Describe the structure of the eye its importance in vision and differentiation of color.','\\text{Describe the structure of the eye \\& its importance in vision and differentiation of color.}','1. Structure of the Eye: The eye consists of the cornea (refraction), iris (aperture control), lens (focal adjustment), and retina (sensory transduction). The retina houses photoreceptors: rods (low light, monochromatic) and cones (bright light, color). 2. Importance in Vision: Light enters through the cornea and pupil, is focused by the lens onto the retina, which converts electromagnetic energy into electrochemical impulses sent via the optic nerve to the brain. 3. Color Differentiation: Cones contain three types of photopsins (S, M, and L) sensitive to short (blue), medium (green), and long (red) wavelengths. Color perception arises from the ratio of excitation across these three cone populations (trichromatic theory).','1. \\text{Structural Components: The eye comprises the cornea (refractive medium), iris (pupil size regulation), crystalline lens (accommodative focusing), and retina (photoreceptor layer). } 2. \\text{Vision Mechanism: Light focalization occurs at the retina, where photons initiate phototransduction. The signal is transmitted through the optic nerve to the visual cortex.} 3. \\text{Color Differentiation: Trichromatic vision is mediated by three cone classes (S, M, L) with peak sensitivities at roughly 420, 530, and 560 nm. The brain processes the differential activation signals of these cones to perceive the visible spectrum.}','Vision relies on retinal photoreception; color differentiation is achieved through trichromatic cone sensitivity to specific electromagnetic wavelengths.','["Eye Structure", "Vision"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('addb599e29ff4ab71fffba93006b1b7c9c6c48a73e4806188a6f37c7bb7e16d1','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.5(a)','Illustrate about genetic engineering and its various applications.','\\text{Illustrate about genetic engineering and its various applications.}','Genetic engineering, or recombinant DNA technology, involves the direct manipulation of an organism\'s genes using biotechnology to alter its characteristics. The process typically follows these steps: 1. Identification and isolation of the target gene. 2. Insertion of the gene into a vector (like a plasmid). 3. Transformation, where the vector is introduced into a host organism. 4. Selection and screening of the modified organisms. Applications include: 1. Medicine (e.g., insulin production, gene therapy for hereditary diseases). 2. Agriculture (e.g., development of pest-resistant crops like Bt cotton, biofortification like Golden Rice). 3. Industry (e.g., production of enzymes and biofuels). 4. Research (e.g., creating model organisms for disease study).','\\text{Genetic engineering involves:} \\\\ 1. \\text{Isolation of DNA fragments.} \\\\ 2. \\text{Insertion into vectors using restriction enzymes and DNA ligase.} \\\\ 3. \\text{Transformation of host cells.} \\\\ 4. \\text{Expression of recombinant proteins.} \\\\ \\text{Key Applications:} \\\\ \\text{Medical: Recombinant insulin production, vaccine development.} \\\\ \\text{Agricultural: Genetically Modified Organisms (GMOs) for herbicide resistance and nutritional enhancement.} \\\\ \\text{Industrial: Microbial synthesis of bio-polymers and enzymes.}','Genetic engineering is the deliberate modification of an organism\'s genetic makeup through recombinant DNA technology, with broad applications in medicine (therapeutics), agriculture (crop improvement), and industry (biotechnology).','["Biotechnology", "Genetic Engineering"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a86968c8b127d67565458d9b2da2b48d7acc4d2f3580d0503a231764e815a25a','End Semester','Unknown Subject (BE24101)','BE24101','5','2024','Q.5(b)','Describe about plant factory its advantages over the conventional production system.','\\text{Describe about plant factory its advantages over the conventional production system.}','1. Definition: A plant factory is a controlled-environment agriculture (CEA) facility that uses artificial lighting, climate control (temperature, humidity, CO2), and hydroponic or aeroponic systems to grow crops indoors, independent of external weather or soil conditions. 2. Comparison with Conventional Systems: Unlike traditional open-field farming, plant factories maximize efficiency through resource optimization. 3. Key Advantages: (a) Increased Productivity: Multi-layer stacking allows for year-round production regardless of climate. (b) Resource Efficiency: Closed-loop systems use up to 90% less water and eliminate pesticide use. (c) Quality Control: Precise environmental management yields consistent nutritional value and uniform growth. (d) Location Independence: Systems can be installed in urban centers, reducing food miles and transportation costs.','\\text{1. Definition: A plant factory is an indoor farming system that optimizes crop production through controlled environment agriculture (CEA), utilizing artificial light, hydroponics, and climate regulation.} \\\\ \\text{2. Advantages over conventional farming: } \\\\ \\text{(a) Yield: Year-round production independent of seasons and weather conditions.} \\\\ \\text{(b) Resource Efficiency: Closed-loop hydroponics reduce water consumption by up to 90\\% compared to soil-based irrigation.} \\\\ \\text{(c) Food Safety: Pesticide-free production due to high-level biosecurity and controlled environment.} \\\\ \\text{(d) Logistics: Reduced food miles through vertical integration in urban settings.}','Plant factories provide superior resource efficiency, higher land-use productivity, and climate-independent, year-round production compared to conventional soil-based agriculture.','["Agricultural Engineering", "Plant Factory"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('9ddbb526f04198933e3d3863a929239f4cd5d11ac0eb262d728750833d286dbd','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.2(a)','What is cell theory?','\\text{What is cell theory?}','Cell theory is a fundamental principle in biology that defines the structural and functional unit of all living organisms. Step 1: All living organisms are composed of one or more cells. Step 2: The cell is the basic unit of structure and organization in organisms. Step 3: All cells arise from pre-existing cells through the process of cell division.','The cell theory states the following three fundamental tenets: (1) \\text{All living organisms are composed of one or more cells.} (2) \\text{The cell is the basic structural and functional unit of life.} (3) \\text{All cells arise from pre-existing cells through division.}','All living things are made of cells; the cell is the basic unit of life; all cells come from pre-existing cells.','["Cell Theory"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3681735ad4bfb733d156d8e2c3e5dd1917095149e5d06e3b138639102c44d75f','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.2(b)','Write the structure and function of Mitochondria.','\\text{Write the structure and function of Mitochondria.}','1. Structure: Mitochondria consist of a double membrane system. The outer membrane is smooth, while the inner membrane is highly folded into structures called cristae, which increase surface area. The space inside the inner membrane is the mitochondrial matrix, containing mitochondrial DNA, ribosomes, and enzymes. 2. Function: Mitochondria serve as the \'powerhouse of the cell\' by performing aerobic respiration. They facilitate the Krebs cycle and the electron transport chain to produce adenosine triphosphate (ATP) through oxidative phosphorylation, converting nutrients into usable chemical energy.','\\text{1. Structure: Mitochondria possess a double-membrane system. The outer membrane acts as a protective boundary, while the inner membrane is invaginated to form cristae, significantly increasing the surface area for biochemical reactions. The internal lumen, or matrix, contains mitochondrial DNA (mtDNA), ribosomes, and enzymatic machinery. 2. Function: Mitochondria are the primary site for ATP synthesis via aerobic respiration. They host the Citric Acid Cycle (Krebs cycle) in the matrix and the Electron Transport Chain (ETC) across the cristae, facilitating oxidative phosphorylation to convert chemical energy from nutrients into adenosine triphosphate (ATP).}','Mitochondria are double-membraned organelles that function as the site of aerobic respiration and ATP production.','["Cell Organelles", "Mitochondria", "Programming Concepts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b6b9a9a85b4526de7e2973012de0fb062e46e1206357f2135b5c9da6c944fe1a','Mid Semester','Unknown Subject (BE24101)','BE24101','2','2024','Q.3(a)','Describe the classification of carbohydrates.','\\text{Describe the classification of carbohydrates.}','Carbohydrates are classified primarily based on the number of sugar units they contain upon hydrolysis. 1. Monosaccharides: The simplest carbohydrates, consisting of a single polyhydroxy aldehyde or ketone unit (e.g., glucose, fructose). They cannot be hydrolyzed further. 2. Oligosaccharides: Carbohydrates that yield 2 to 10 monosaccharide units upon hydrolysis. These are further classified as disaccharides (two units, e.g., sucrose), trisaccharides, etc. 3. Polysaccharides: Complex carbohydrates that yield a large number (often hundreds or thousands) of monosaccharide units upon hydrolysis (e.g., starch, cellulose, glycogen).','\\text{Carbohydrates are classified into three main groups based on their structural complexity and hydrolysis products:} \\\\ 1. \\text{Monosaccharides: Simple sugars that cannot be hydrolyzed into smaller carbohydrate molecules (e.g., } C_6H_{12}O_6 \\text{).} \\\\ 2. \\text{Oligosaccharides: Yield 2-10 monosaccharide units upon hydrolysis. Disaccharides are the most common subclass (e.g., Sucrose } \\rightarrow \\text{ Glucose + Fructose).} \\\\ 3. \\text{Polysaccharides: High molecular weight polymers yielding many monosaccharide units upon complete hydrolysis (e.g., } (C_6H_{10}O_5)_n \\text{).}','Monosaccharides, Oligosaccharides, and Polysaccharides','["Biomolecules", "Carbohydrates"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('65d8d120935674b334177df03029793aeccf2d918a71cb853e76934c99847eb8','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2024','Q.3(b)','What is meiosis? Discuss the significance of meiosis.','\\text{What is meiosis? Discuss the significance of meiosis.}','Meiosis is a specialized type of cell division that reduces the chromosome number by half, resulting in four genetically distinct haploid daughter cells (gametes) from a single diploid parent cell. It involves one round of DNA replication followed by two successive rounds of nuclear division: Meiosis I (reductional division) and Meiosis II (equational division). The significance of meiosis includes: 1. Maintenance of Chromosome Number: By halving the chromosome count, it ensures that fertilization restores the characteristic diploid number of the species, preventing doubling in each generation. 2. Genetic Variation: Through independent assortment of homologous chromosomes and crossing-over (recombination) during Prophase I, it creates unique genetic combinations, providing the raw material for natural selection and evolution.','Meiosis is a specialized eukaryotic cell division process characterized by two successive divisions (Meiosis I and II) following a single round of DNA replication, reducing a diploid (2n) cell to four haploid (n) daughter cells. \\text{Significance:} \\begin{enumerate} \\item \\textbf{Maintenance of Ploidy:} Ensures the restoration of diploidy upon fertilization, preventing chromosome doubling per generation (2n + 2n \\rightarrow 4n would occur in mitosis-only cycles). \\item \\textbf{Genetic Diversity:} 1. \\textit{Crossing-over:} Recombination between non-sister chromatids creates new allele combinations. 2. \\textit{Independent Assortment:} Random alignment of homologous pairs during Metaphase I generates $2^n$ possible gametic combinations. \\end{enumerate}','Meiosis is a reductional cell division essential for sexual reproduction, ensuring constant chromosome numbers across generations and generating genetic diversity via recombination and independent assortment.','["Cell Division", "Meiosis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('00fcd89c00f0cef1e8d65353ea7947a1d39c3daf46ec21f0006d07a18eb93a16','Mid Semester','Unknown Subject (BE24101)','BE24101','2','2024','Q.4(a)','What are the functions of proteins?','\\text{What are the functions of proteins?}','Proteins are versatile macromolecules that perform essential biological roles: 1. Enzymatic catalysis: Speeding up biochemical reactions (e.g., DNA polymerase). 2. Structural support: Providing mechanical strength and shape (e.g., collagen, keratin). 3. Transport: Moving molecules across membranes or through fluids (e.g., hemoglobin, membrane channels). 4. Signaling and Regulation: Acting as hormones or receptors to coordinate physiological processes (e.g., insulin). 5. Defense: Protecting the body against pathogens (e.g., antibodies). 6. Storage: Holding essential nutrients for later use (e.g., ferritin). 7. Movement: Enabling mechanical work through contraction (e.g., actin and myosin).','\\text{Proteins perform diverse biological functions: } \\begin{enumerate} \\item \\text{Catalysis: Enzymes lower activation energy for metabolic reactions.} \\item \\text{Structure: Fibrous proteins like collagen provide mechanical integrity.} \\item \\text{Transport: Carrier proteins move substances across membranes.} \\item \\text{Regulation: Hormonal proteins act as chemical messengers.} \\item \\text{Defense: Immunoglobulins recognize and neutralize pathogens.} \\item \\text{Contractility: Motor proteins like myosin facilitate muscle contraction.} \\end{enumerate}','Proteins function in catalysis, structure, transport, signaling, defense, storage, and movement.','["Biomolecules", "Programming Concepts", "Proteins"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('138822239096beff55d67ef56f208ce19e00994cb75322ce3d227982175f1a92','Mid Semester','Unknown Subject (BE24101)','BE24101','3','2024','Q.5(a)','State the first law of thermodynamics and give a suitable mathematical expression for it.','\\text{State the first law of thermodynamics and give a suitable mathematical expression for it.}','Step 1: Define the first law of thermodynamics, which is a statement of the law of conservation of energy applied to thermodynamic systems. It states that energy cannot be created or destroyed, only transformed or transferred. Step 2: Express the law mathematically by considering the change in internal energy of a closed system. The internal energy change (dU) is equal to the sum of the heat added to the system (dQ) and the work done on the system (dW). Step 3: Write the final equation, noting the sign convention where dW is positive for work done on the system, leading to dU = dQ + dW.','The first law of thermodynamics states that the internal energy of an isolated system is constant, or more generally, for any process, the change in internal energy of a closed system is equal to the net heat added to the system plus the net work done on the system. Mathematically, this is expressed as: dU = dQ + dW, where dU represents the change in internal energy, dQ is the infinitesimal heat transferred to the system, and dW is the infinitesimal work done on the system.','dU = dQ + dW','["Bioenergetics", "Engineering Thermodynamics", "Thermodynamics"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('19ec84a6310752cad4d1b22e3defa76a2ef52a0e4fa39b5cc8880b9acdc7598f','Mid Semester','Unknown Subject (BE24101)','BE24101','3','2024','Q.5(b)','Distinguish between aerobic and anaerobic respiration with suitable examples.','\\text{Distinguish between aerobic and anaerobic respiration with suitable examples.}','Step 1: Define aerobic respiration as a process requiring oxygen to completely break down glucose into carbon dioxide and water, yielding high energy (36-38 ATP). Step 2: Define anaerobic respiration as a process occurring in the absence of oxygen, where glucose is partially broken down into ethanol/lactic acid and CO2, yielding low energy (2 ATP). Step 3: Provide examples: Aerobic respiration occurs in most eukaryotic cells (e.g., human muscle cells during rest, plant cells). Anaerobic respiration occurs in yeast cells (ethanol fermentation) and human muscle cells during intense exercise (lactic acid fermentation).','\\text{1. Aerobic Respiration: Occurs in the presence of oxygen, resulting in the complete oxidation of glucose into } CO_2, H_2O, \\text{ and high energy yield (36-38 ATP). Example: Cellular respiration in human muscle cells at rest. Equation: } C_6H_{12}O_6 + 6O_2 \\rightarrow 6CO_2 + 6H_2O + 38ATP. \\\\ \\text{2. Anaerobic Respiration: Occurs in the absence of oxygen, resulting in the partial breakdown of glucose into ethanol or lactic acid with low energy yield (2 ATP). Example: Fermentation in yeast. Equation: } C_6H_{12}O_6 \\rightarrow 2C_2H_5OH + 2CO_2 + 2ATP.','Aerobic respiration produces 38 ATP via complete glucose oxidation using oxygen (e.g., human muscle cells), whereas anaerobic respiration produces 2 ATP via partial oxidation without oxygen (e.g., yeast fermentation).','["Metabolism", "Respiration"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('5f6a2a2d1a502d44fd3010bc4f6cf015a8b528b17e8db1a3a0c5f7069498d352','End Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.1(b)','Define animal cell structure and discuss any two organelles.','\\text{Define animal cell structure and discuss any two organelles.}','1. Definition: An animal cell is a type of eukaryotic cell that lacks a cell wall and chloroplasts, characterized by a plasma membrane, a membrane-bound nucleus containing genetic material, and various membrane-bound organelles suspended in the cytoplasm. 2. Organelle 1: Mitochondria are double-membraned organelles known as the powerhouses of the cell, where aerobic respiration occurs to produce ATP. 3. Organelle 2: The Endoplasmic Reticulum (ER) is a network of membranes involved in protein synthesis (Rough ER, due to ribosomes) and lipid synthesis/detoxification (Smooth ER).','\\text{1. Definition: An animal cell is a eukaryotic cell comprising a plasma membrane, cytoplasm, and membrane-bound organelles, lacking a rigid cell wall. 2. Mitochondria: These are double-membrane organelles responsible for cellular respiration, converting nutrients into adenosine triphosphate (ATP) through oxidative phosphorylation. 3. Endoplasmic Reticulum (ER): A system of interconnected membranes divided into Rough ER (studded with ribosomes for protein synthesis) and Smooth ER (responsible for lipid metabolism and detoxification).}','Animal cells are eukaryotic cells without cell walls. Mitochondria generate ATP, and the Endoplasmic Reticulum synthesizes proteins and lipids.','["Animal Cells", "Cell Organelles"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3f906d7e3552def68afbc256541a1089579b3e3fd7d840e929f2f1e44b05f63f','End Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.2(a)','State the stages of Electron Transport Chain with diagram.','\\text{State the stages of Electron Transport Chain with diagram.}','The Electron Transport Chain (ETC) is a series of protein complexes located in the inner mitochondrial membrane that facilitate the transfer of electrons from NADH and FADH2 to oxygen. Step 1: Complex I (NADH dehydrogenase) accepts electrons from NADH, pumping protons into the intermembrane space. Step 2: Complex II (Succinate dehydrogenase) accepts electrons from FADH2. Step 3: Coenzyme Q (Ubiquinone) transfers electrons from Complexes I and II to Complex III. Step 4: Complex III (Cytochrome bc1 complex) transfers electrons to Cytochrome c while pumping protons. Step 5: Cytochrome c carries electrons to Complex IV (Cytochrome c oxidase). Step 6: Complex IV transfers electrons to oxygen to form water and pumps protons. The resulting proton gradient drives ATP synthase to produce ATP. For the diagram: Imagine a membrane with Complexes I, II, III, and IV embedded. NADH/FADH2 enter at the top, electrons flow right through carriers (Q, Cyt c), protons move from the matrix to the intermembrane space, and O2 + H+ exit as H2O.','\\text{The Electron Transport Chain (ETC) stages are as follows:} \\\\ \\text{1. Complex I (NADH dehydrogenase): Receives electrons from NADH. Protons (H^+) are pumped into the intermembrane space.} \\\\ \\text{2. Complex II (Succinate dehydrogenase): Receives electrons from FADH}_2. \\\\ \\text{3. Ubiquinone (Coenzyme Q): Acts as an electron carrier between Complexes I/II and Complex III.} \\\\ \\text{4. Complex III (Cytochrome bc}_1 \\text{ complex): Transfers electrons to Cytochrome c and pumps protons.} \\\\ \\text{5. Cytochrome c: Shuttles electrons to Complex IV.} \\\\ \\text{6. Complex IV (Cytochrome c oxidase): Transfers electrons to O}_2 \\text{, reducing it to H}_2\\text{O, and pumps protons.} \\\\ \\text{Diagram description: [Matrix] -> [Complex I, II, III, IV in Inner Membrane] -> [Intermembrane Space]. Electrons flow: NADH/FADH}_2 \\rightarrow \\text{Complex I/II} \\rightarrow \\text{Q} \\rightarrow \\text{Complex III} \\rightarrow \\text{Cyt c} \\rightarrow \\text{Complex IV} \\rightarrow \\text{O}_2 \\rightarrow \\text{H}_2\\text{O}. \\text{Protons flow from matrix to intermembrane space through Complexes I, III, and IV.}','The ETC involves four membrane-bound complexes (I-IV) that oxidize electron carriers (NADH, FADH2), pump protons to create a gradient, and reduce O2 to H2O to power ATP synthase.','["Electron Transport Chain", "Respiration"]','conceptual','0.98',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('9ffa74f6571c8c349cd4b02b6dfa90bdc3c3325c471d3d9f0f9ab9fc217db180','End Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.2(b)','Discuss the light reaction of photosynthesis with diagram.','\\text{Discuss the light reaction of photosynthesis with diagram.}','The light reaction of photosynthesis occurs in the thylakoid membranes of chloroplasts and converts light energy into chemical energy (ATP and NADPH). 1. Photon absorption: Photosystems II (PSII) and I (PSI) absorb photons, exciting chlorophyll electrons to higher energy levels. 2. Photolysis: Water molecules are split by the oxygen-evolving complex at PSII, releasing electrons, protons (H+), and oxygen gas (O2). 3. Electron Transport Chain (ETC): Excited electrons from PSII travel through plastoquinone, the cytochrome b6f complex, and plastocyanin. This movement powers proton pumping into the thylakoid lumen. 4. ATP Synthesis: The proton gradient established drives ATP synthase to phosphorylate ADP into ATP (photophosphorylation). 5. NADPH Formation: Electrons from PSI are transferred through ferredoxin to NADP+ reductase, reducing NADP+ to NADPH. The overall result is the conversion of light into chemical energy.','\\text{The light-dependent reactions occur in the thylakoid membrane through the following steps:} \\\\ 1. \\text{Photon absorption: PSII (P680) absorbs light, exciting electrons.} \\\\ 2. \\text{Photolysis: } 2H_2O \\rightarrow 4H^+ + 4e^- + O_2. \\\\ 3. \\text{Electron Transport: Electrons pass through Plastoquinone (PQ), Cytochrome } b_6f, \\text{ and Plastocyanin (PC).} \\\\ 4. \\text{Chemiosmosis: The proton gradient powers ATP synthase to produce ATP from ADP + Pi.} \\\\ 5. \\text{Reduction: PSI (P700) absorbs light, and electrons reduce } NADP^+ \\text{ to } NADPH \\text{ via Ferredoxin-NADP}^+ \\text{ reductase.} \\\\ \\text{Overall equation: } 12H_2O + 12NADP^+ + 18ADP + 18P_i \\xrightarrow{\\text{light}} 6O_2 + 12NADPH + 18ATP.','Conversion of light energy into chemical energy (ATP and NADPH) through non-cyclic photophosphorylation.','["Light Reaction", "Photosynthesis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('1d54c1314eb17f886d6faff7068ba483aa95728710ef1229d45c0fa416c6d1fe','End Semester','Unknown Subject (BE24101)','BE24101','2','2023','Q.3(a)','Describe lock and key model for enzyme-substrate.','\\text{Describe lock and key model for enzyme-substrate.}','1. Concept Introduction: The lock and key model, proposed by Emil Fischer in 1894, describes enzyme-substrate specificity. 2. Mechanism: The enzyme\'s active site acts as a rigid lock, and the substrate acts as a specific key. 3. Interaction: Only a substrate with a geometry exactly complementary to the active site can bind. 4. Formation: Binding forms an enzyme-substrate (ES) complex. 5. Reaction: Once bound, the substrate is converted into products, which then dissociate from the enzyme, leaving the enzyme unchanged.','1. \\text{Concept: The model posits that the enzyme\'s active site is a rigid structural entity with a fixed shape.} \\\\ 2. \\text{Binding Mechanism: The substrate is viewed as a specific key that fits precisely into the lock (the enzyme active site).} \\\\ 3. \\text{Specificity: Catalysis occurs only if the substrate configuration matches the active site shape perfectly, leading to the formation of an Enzyme-Substrate (ES) complex.} \\\\ 4. \\text{Reaction Cycle: E + S \\rightleftharpoons ES \\rightarrow E + P, where E is the enzyme, S the substrate, and P the product. The enzyme remains unaltered post-reaction.}','The lock and key model asserts that enzyme-substrate specificity is due to the rigid, complementary geometric shapes of the active site and the substrate.','["Enzymes", "Lock and Key Model"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('501a8db4e2d935989c2d62f90af719c8abe24b351b8e80f3a22fc522c4ed6a1c','End Semester','Unknown Subject (BE24101)','BE24101','5','2023','Q.3(b)','Discuss any one technique of enzyme immobilization and its application.','\\text{Discuss any one technique of enzyme immobilization and its application.}','Covalent binding is a primary technique for enzyme immobilization. Step 1: Functionalization of the support matrix involves activating a carrier (like silica, cellulose, or synthetic polymers) with reactive groups such as glutaraldehyde or cyanogen bromide. Step 2: The enzyme is introduced to the activated support under controlled pH and temperature, allowing the formation of stable covalent bonds between the enzyme\'s surface functional groups (usually amino groups of lysine residues) and the support. Step 3: Unbound enzymes are removed through extensive washing. An application of this technique is in the food industry, specifically for the immobilization of lactase on a solid support to hydrolyze lactose into glucose and galactose for lactose-free milk production.','\\text{1. \\textbf{Technique: Covalent Binding}} \\\\ \\text{This method involves the formation of stable chemical bonds between the enzyme\'s functional groups (e.g., -NH}_2, \\text{-COOH, -SH) and a chemically activated support matrix (e.g., controlled pore glass, synthetic resins). Common coupling agents include glutaraldehyde or carbodiimides. The reaction is typically represented as: } \\\\ \\text{Support + Coupling Agent} \\rightarrow \\text{Activated Support} \\\\ \\text{Activated Support + Enzyme} \\rightarrow \\text{Support-Enzyme Conjugate} \\\\ \\text{2. \\textbf{Application: Lactose Hydrolysis}} \\\\ \\text{Covalently immobilized lactase is used in industrial bioreactors to treat whey or milk. By anchoring the enzyme to a matrix, it becomes resistant to leaching and thermal denaturation, allowing continuous processing and product purity, which is critical in the production of lactose-free dairy products.}','Covalent binding, applied in the industrial production of lactose-free milk.','["Enzyme Immobilization"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('ea8942f2fed3f3a5c5674ba4cda3fd0fbf011594c7217a6839001cef0829aef8','End Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.4(b)','Write the structure and function of ear.','\\text{Write the structure and function of ear.}','The ear is a sensory organ responsible for hearing and equilibrium, divided into three anatomical regions: 1. Outer Ear: Comprises the pinna (auricle) and external auditory canal. It collects and funnels sound waves toward the tympanic membrane. 2. Middle Ear: Contains the tympanic cavity and three ossicles (malleus, incus, stapes). Its function is to amplify mechanical vibrations from the eardrum and transmit them to the inner ear via the oval window. 3. Inner Ear: Includes the cochlea (responsible for hearing via hair cells) and the vestibular system (semicircular canals and otolith organs for balance). It transduces mechanical vibrations into electrical nerve impulses sent to the brain via the vestibulocochlear nerve (CN VIII).','\\text{The ear is anatomically divided into three segments:} \\\\ \\text{1. Outer Ear: Includes the pinna and auditory canal; function is sound collection.} \\\\ \\text{2. Middle Ear: Includes the tympanic membrane and ossicles (malleus, incus, stapes); function is impedance matching and sound amplification.} \\\\ \\text{3. Inner Ear: Includes the cochlea for auditory transduction and the vestibular apparatus (semicircular canals) for equilibrium and balance.} \\\\ \\text{Overall Process: Sound waves} \\rightarrow \\text{mechanical vibration} \\rightarrow \\text{fluid displacement} \\rightarrow \\text{neural signal transmission via CN VIII.}','\\text{Structure: Outer, Middle, Inner Ear; Function: Audition and Equilibrium}','["Ear Structure", "Programming Concepts", "Sensory Systems"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('fbd06e53be7a7f0ad07abf799c05a46968df6f58951dc44363721467ac0c0c31','End Semester','Unknown Subject (BE24101)','BE24101','5','2023','Q.5(b)','Describe Various components and applications of PCR.','\\text{Describe Various components and applications of PCR.}','Polymerase Chain Reaction (PCR) is a technique to amplify DNA segments. The components include: 1) DNA Template: The target DNA sequence. 2) Primers: Short single-stranded DNA sequences flanking the target region. 3) DNA Polymerase: A heat-stable enzyme (e.g., Taq polymerase) that synthesizes the new strand. 4) dNTPs: Building blocks (A, T, C, G) for DNA synthesis. 5) Buffer Solution: Provides optimal pH and chemical environment, including divalent cations like Mg2+. Applications include: 1) Clinical Diagnostics: Detecting pathogens or genetic mutations. 2) Forensics: DNA profiling and identification. 3) Research: Gene cloning, sequencing, and expression analysis. 4) Evolutionary Biology: Studying ancient DNA.','\\text{The PCR components are: } \\text{1) Template DNA; 2) Taq DNA Polymerase; 3) Primers (forward and reverse); 4) dNTPs (deoxynucleotide triphosphates); 5) Buffer containing Mg}^{2+} \\text{ ions. Applications include: } \\text{1) Molecular diagnostics (pathogen detection); 2) Forensic science (DNA fingerprinting); 3) Molecular cloning and sequencing; 4) Genetic engineering and gene expression studies.}','PCR components: DNA template, Primers, Taq polymerase, dNTPs, and Buffer. Applications: Diagnostics, Forensics, Cloning, and Genetic Research.','["Biotechnology Tools", "PCR"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('973382fd5a4e6a368d11d4f28da4c1e32c6be3ef7b9262de81099d1949fe8381','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.1(a)','What are the various stages of biological organization?','\\text{What are the various stages of biological organization?}','Biological organization represents the hierarchy of complex biological structures and systems. The stages, from simplest to most complex, are: 1. Atom: The smallest unit of matter. 2. Molecule: Chemical structures consisting of two or more atoms. 3. Organelle: Functional components within cells. 4. Cell: The basic unit of life. 5. Tissue: A group of similar cells performing a specific function. 6. Organ: A structure composed of tissues working together. 7. Organ System: A group of organs performing complex physiological tasks. 8. Organism: An individual living entity. 9. Population: Groups of individuals of the same species in a specific area. 10. Community: All populations in a given area. 11. Ecosystem: Living organisms and their physical environment. 12. Biosphere: The global sum of all ecosystems.','The hierarchy of biological organization proceeds as follows: \\text{Atom} \\rightarrow \\text{Molecule} \\rightarrow \\text{Organelle} \\rightarrow \\text{Cell} \\rightarrow \\text{Tissue} \\rightarrow \\text{Organ} \\rightarrow \\text{Organ System} \\rightarrow \\text{Organism} \\rightarrow \\text{Population} \\rightarrow \\text{Community} \\rightarrow \\text{Ecosystem} \\rightarrow \\text{Biosphere}.','Atom, Molecule, Organelle, Cell, Tissue, Organ, Organ System, Organism, Population, Community, Ecosystem, Biosphere','["Biological Organization"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('2e3f853fdf613c5d2adf8e17cb9c3d74756043f21eba418c606e8047548adf7a','Mid Semester','Unknown Subject (BE24101)','BE24101','2','2023','Q.2(a)','Write the sources and disorder caused by vitamin A and vitamin B1.','\\text{Write the sources and disorder caused by vitamin A and vitamin B1.}','Step 1: Identify Vitamin A (Retinol). Sources include liver, fish oil, eggs, dairy, and orange/yellow vegetables like carrots (carotenoids). Deficiency causes night blindness (nyctalopia), xerophthalmia (dry eyes), and impaired immune function. Step 2: Identify Vitamin B1 (Thiamine). Sources include whole grains, legumes, pork, seeds, and nuts. Deficiency causes Beriberi (characterized by peripheral neuropathy, muscle wasting, and heart failure) and Wernicke-Korsakoff syndrome (common in alcoholics, involving neurological impairment).','\\text{Step 1: Vitamin A (Retinol). Sources: Liver, fish oil, eggs, dairy, carrots, sweet potatoes. Disorders: Night blindness (nyctalopia), xerophthalmia, and follicular hyperkeratosis. Step 2: Vitamin B1 (Thiamine). Sources: Whole grains, legumes, pork, yeast, nuts. Disorders: Beriberi (wet or dry) and Wernicke-Korsakoff syndrome.}','Vitamin A: Sources: Liver, carrots. Disorders: Night blindness. Vitamin B1: Sources: Whole grains, legumes. Disorders: Beriberi.','["Biomolecules", "Vitamins"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('0a44fb24e816942393f0edef5d2ce6b12d91d95387c752dbbccce36bc7823980','Mid Semester','Unknown Subject (BE24101)','BE24101','2','2023','Q.4(a)','What are the levels of protein structure?','\\text{What are the levels of protein structure?}','The structure of proteins is hierarchical, organized into four distinct levels: 1. Primary structure: The linear sequence of amino acids in a polypeptide chain connected by peptide bonds. 2. Secondary structure: Localized folding patterns of the polypeptide backbone, primarily stabilized by hydrogen bonds between the carbonyl oxygen and amide hydrogen, forming alpha-helices and beta-pleated sheets. 3. Tertiary structure: The overall three-dimensional conformation of a single polypeptide chain, determined by R-group interactions such as hydrophobic effects, ionic bonds, disulfide bridges, and van der Waals forces. 4. Quaternary structure: The arrangement and interaction of multiple folded polypeptide subunits into a single functional protein complex.','\\text{The protein structure is categorized into four levels:} \\\\ 1. \\text{Primary: The linear sequence of amino acids joined by peptide bonds.} \\\\ 2. \\text{Secondary: Regular repeating conformations (}\\alpha\\text{-helices and }\\beta\\text{-sheets) stabilized by hydrogen bonding between the backbone.} \\\\ 3. \\text{Tertiary: The global 3D fold resulting from R-group side chain interactions (hydrophobic, ionic, disulfide, van der Waals).} \\\\ 4. \\text{Quaternary: The spatial assembly of multiple polypeptide subunits into a functional multi-mer.}','Primary, Secondary, Tertiary, and Quaternary structures.','["Biomolecules", "Protein Structure"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4e08716e1082da8a123155ea593e6f9779ded9b167a33df6ba609194f59c8613','Mid Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.5(a)','What is Gibbs Free Energy?','\\text{What is Gibbs Free Energy?}','1. Definition: Gibbs Free Energy (G) is a thermodynamic potential that measures the maximum reversible work that may be performed by a thermodynamic system at constant temperature and pressure.\n2. Mathematical formula: It is defined as G = H - TS, where H is enthalpy, T is absolute temperature, and S is entropy.\n3. Change in Gibbs Free Energy: For a process at constant temperature and pressure, the change is given by ΔG = ΔH - TΔS.\n4. Criterion for spontaneity: If ΔG < 0, the process is spontaneous; if ΔG = 0, the system is at equilibrium; if ΔG > 0, the process is non-spontaneous.','G = H - TS. \\text{ For a process at constant temperature and pressure, the change in Gibbs free energy is defined as: } \\Delta G = \\Delta H - T\\Delta S. \\text{ Spontaneity is determined by: } \\Delta G < 0 \\implies \\text{spontaneous}, \\Delta G = 0 \\implies \\text{equilibrium}, \\Delta G > 0 \\implies \\text{non-spontaneous}.','G = H - TS','["Bioenergetics", "Gibbs Free Energy", "Thermodynamics"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('51748638fa310a7c47f5f9058c7fb88592f3d3e730c01f30dbe5d6c6df51b899','Mid Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.5(b)','Write note on aerobic and anaerobic respiration and its location in cell.','\\text{Write note on aerobic and anaerobic respiration and its location in cell.}','1. Aerobic respiration is a metabolic process that requires oxygen to convert glucose into energy (ATP). It involves glycolysis, the Krebs cycle, and the electron transport chain. In eukaryotic cells, glycolysis occurs in the cytoplasm, while the Krebs cycle and electron transport chain occur in the mitochondria. The net reaction is C6H12O6 + 6O2 -> 6CO2 + 6H2O + ATP. 2. Anaerobic respiration occurs in the absence of oxygen. It involves glycolysis followed by fermentation (lactic acid or alcoholic). The entire process occurs in the cytoplasm of the cell. It yields significantly less ATP compared to aerobic respiration.','\\text{1. Aerobic Respiration: Occurs in the presence of } O_2. \\text{ Stages include glycolysis (cytoplasm), Krebs cycle (mitochondrial matrix), and ETC (inner mitochondrial membrane). Overall reaction: } C_6H_{12}O_6 + 6O_2 \\rightarrow 6CO_2 + 6H_2O + 36-38 ATP. \\text{ 2. Anaerobic Respiration: Occurs in the absence of } O_2. \\text{ It involves glycolysis followed by fermentation, entirely within the cytoplasm. Net yield: 2 ATP.}','Aerobic respiration occurs in the cytoplasm and mitochondria (yields 36-38 ATP); anaerobic respiration occurs in the cytoplasm (yields 2 ATP).','["Cellular Location", "Respiration"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('dd4321509ee5965006f94d1b3e75162c8fb9c1144873b0376d1ee5340b18de47','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.1(a)','Draw a schematic diagram of cell cycle.','\\text{Draw a schematic diagram of cell cycle.}','The cell cycle is the ordered series of events leading to cell division. It consists of two major phases: Interphase and M-phase (Mitosis). 1. Interphase: This is the longest phase, where the cell grows and prepares for division. It is divided into three sub-phases: G1 (Gap 1 phase, cell growth and protein synthesis), S (Synthesis phase, DNA replication), and G2 (Gap 2 phase, preparation for mitosis). 2. M-phase: This phase involves mitosis (nuclear division) and cytokinesis (cytoplasmic division). A schematic representation typically shows these phases in a circular diagram: G1 leads to S, S leads to G2, and G2 leads to M, which cycles back to G1. A G0 phase (quiescence) branches out from G1.','The \\text{cell cycle} \\text{ is represented as a cyclical process consisting of: } \\newline 1. \\text{ Interphase: } \\{G_1 \\to S \\to G_2\\} \\newline 2. \\text{ M-phase (Mitosis/Cytokinesis): } \\text{M} \\newline \\text{The cycle follows the sequence: } G_1 \\to S \\to G_2 \\to M \\to G_1. \\text{ The } G_0 \\text{ phase is a resting state branching from } G_1.','G_1 \\to S \\to G_2 \\to M \\to G_1','["Cell Cycle"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('321aa6084fd0248525de5914381b534359f85a3fc27001b9e74fc1c58937ff4a','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.1(b)','Who gave the Chemosynthetic theory for the origin of life? Describe an experiment to prove the Chemosynthetic theory of the origin of life.','\\text{Who gave the Chemosynthetic theory for the origin of life? Describe an experiment to prove the Chemosynthetic theory of the origin of life.}','1. Conceptual Analysis: The Chemosynthetic Theory (Oparin-Haldane hypothesis) posits that life originated from non-living organic molecules that formed through chemical evolution in the Earth\'s primitive reducing atmosphere. This process involved the synthesis of simple organic compounds (monomers) followed by complex polymers. 2. Experimental Proof: The theory was experimentally validated by Stanley Miller and Harold Urey in 1953. Their apparatus simulated the conditions of the primordial atmosphere. 3. Working: Miller and Urey used a closed system containing methane, ammonia, hydrogen, and water vapor (mimicking the early atmosphere). They subjected this mixture to electric discharges (simulating lightning) while maintaining high temperatures. After a week, the analysis of the condensed liquid revealed the presence of amino acids, the building blocks of proteins. 4. Interpretation: The results demonstrated that organic compounds essential for life could arise spontaneously from inorganic precursors under abiotic conditions, thereby providing empirical evidence for chemical evolution.','\\text{1. Theory: The Chemosynthetic theory was proposed by Alexander Oparin and J.B.S. Haldane. It suggests that life evolved through a series of chemical reactions in the early Earth\'s atmosphere (rich in CH}_4\\text{, NH}_3\\text{, H}_2\\text{, and H}_2\\text{O}). \\\\ \\text{2. Experiment: The Miller-Urey experiment (1953) serves as the primary proof.} \\\\ \\text{3. Setup: A closed apparatus with a flask containing CH}_4\\text{, NH}_3\\text{, H}_2\\text{, and H}_2\\text{O vapor was subjected to electrical sparks (at 800}^\\circ\\text{C). A condenser cooled the gases to liquid, which was collected.} \\\\ \\text{4. Result: Analysis showed the formation of amino acids like glycine, alanine, and aspartic acid.} \\\\ \\text{5. Conclusion: The experiment confirmed that abiotic synthesis of organic molecules is chemically feasible under primitive Earth conditions.}','The theory was proposed by Oparin and Haldane; proof provided by the Miller-Urey experiment showing the synthesis of amino acids from inorganic precursors.','["Chemosynthetic Theory", "Origin of Life"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c3452fb225933c59aadfe2b3cf56857c8eb96045bdf57ae5d4fa8ba9b76e1e65','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.2(a)','Differentiate between Mitosis and Meiosis.','\\text{Differentiate between Mitosis and Meiosis.}','1. Definition: Mitosis is a type of cell division resulting in two genetically identical daughter cells, while Meiosis results in four genetically distinct daughter cells. 2. Purpose: Mitosis is for growth, tissue repair, and asexual reproduction. Meiosis is specifically for the production of gametes for sexual reproduction. 3. Number of Divisions: Mitosis involves one single nuclear division. Meiosis involves two successive nuclear divisions (Meiosis I and II). 4. Ploidy: In Mitosis, the chromosome number remains constant (diploid to diploid). In Meiosis, the chromosome number is halved (diploid to haploid). 5. Genetic Variation: Mitosis maintains genetic uniformity, whereas Meiosis introduces genetic diversity through crossing over and independent assortment.','\\begin{enumerate} \\item \\textbf{Definition:} Mitosis produces two identical diploid somatic cells. Meiosis produces four non-identical haploid gametes. \\item \\textbf{Nuclear Divisions:} Mitosis comprises one division phase. Meiosis comprises two phases: Meiosis I (reductional) and Meiosis II (equational). \\item \\textbf{Chromosome Number:} Mitosis preserves $2n \\rightarrow 2n$. Meiosis reduces $2n \\rightarrow n$. \\item \\textbf{Genetic Recombination:} Mitosis lacks crossing over. Meiosis involves synapsis and crossing over during Prophase I. \\end{enumerate}','Mitosis: Identical diploid cells; Meiosis: Distinct haploid gametes.','["Cell Division", "Meiosis", "Mitosis"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c6c89fb9c20045cb457aebf0e09264eff6ff6762eae879f911d4263787556046','Mid Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.2(b)','Who proposed cell theory? Discuss its components and limitations.','\\text{Who proposed cell theory? Discuss its components and limitations.}','1. Identification: Cell theory was proposed by Matthias Schleiden and Theodor Schwann in the 1830s, later expanded by Rudolf Virchow. 2. Components: The theory states: (a) All living organisms are composed of one or more cells. (b) The cell is the basic structural and functional unit of life. (c) All cells arise from pre-existing cells (Omnis cellula e cellula). 3. Limitations: (a) Viruses are considered non-cellular and challenge the universality of the theory. (b) Mitochondria and chloroplasts contain their own genetic material and replicate independently, which suggests a complex evolutionary origin. (c) Coenocytic organisms (e.g., certain algae and fungi) consist of multinucleated masses without distinct cell boundaries, challenging the concept of the cell as a discrete unit.','\\text{1. Proposed by: Matthias Schleiden and Theodor Schwann (1838-1839), extended by Rudolf Virchow (1855).} \\\\ \\text{2. Core Components:} \\\\ \\text{a) All living organisms consist of one or more cells.} \\\\ \\text{b) The cell is the fundamental unit of structure and function.} \\\\ \\text{c) New cells originate from pre-existing cells via division (Omnis cellula e cellula).} \\\\ \\text{3. Limitations:} \\\\ \\text{a) Viruses: Lack cellular machinery, yet replicate inside hosts.} \\\\ \\text{b) Non-cellular structures: Coenocytic fungi/algae exhibit multinucleate cytoplasm without clear division.} \\\\ \\text{c) Organelles: Mitochondria and chloroplasts possess semi-autonomous DNA, implying endosymbiotic origins not fully explained by original cell theory.}','Schleiden and Schwann proposed the theory; it defines cells as the units of life but is limited by viruses, coenocytic structures, and semi-autonomous organelles.','["Cell Theory", "History of Biology"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('702338e17b528561964ed80f3164b7170664c5bb4ae29fd90d014c42261511ad','Mid Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.4(a)','Define Entropy. Does photosynthesis reduce local entropy?','\\text{Define Entropy. Does photosynthesis reduce local entropy?}','1. Analysis: Entropy (S) is a thermodynamic state function quantifying the number of microscopic configurations consistent with a macroscopic state, representing disorder or energy unavailability. According to the Second Law of Thermodynamics, the total entropy of an isolated system must increase over time. 2. Conceptualization: Photosynthesis converts CO2 and H2O into glucose (C6H12O6) and O2. This process organizes atoms into complex molecular structures, which appears to decrease local entropy within the biological system. 3. Interpretation: While the local entropy of the plant decreases, the process requires solar energy input. The heat dissipated into the environment during energy transduction increases the entropy of the surroundings by a greater magnitude than the local decrease, ensuring the total entropy of the universe increases, satisfying the Second Law.','Definition: S = k_B \\ln(\\Omega), where S is entropy, k_B is the Boltzmann constant, and \\Omega is the number of microstates. For photosynthesis: 6CO_2 + 6H_2O + \\text{light energy} \\rightarrow C_6H_{12}O_6 + 6O_2. \\Delta S_{local} < 0 due to the formation of complex biomass from simple molecules. However, the system is not isolated. The Second Law states \\Delta S_{total} = \\Delta S_{local} + \\Delta S_{surroundings} \\geq 0. Since photosynthesis is coupled with the dissipation of solar energy as heat, |\\Delta S_{surroundings}| > |\\Delta S_{local}|, resulting in \\Delta S_{total} > 0.','Entropy is a measure of molecular disorder or the number of accessible microstates. Photosynthesis does reduce local entropy, but it increases the entropy of the surroundings through heat dissipation, resulting in a net increase in total entropy.','["Bioenergetics", "Entropy", "Photosynthesis", "Thermodynamics"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('7139a646e6225594c9a027532a705e70d65ceaea9e885e6e935e5753b800cca3','Mid Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.5(b)','What are the 5 differences between aerobics and anaerobic respiration? Is there any similarity between them?','\\text{What are the 5 differences between aerobics and anaerobic respiration? Is there any similarity between them?}','Conceptual analysis: Aerobic and anaerobic respiration are two primary pathways for ATP production in cells. Aerobic respiration relies on oxygen as a terminal electron acceptor in the electron transport chain, while anaerobic respiration/fermentation utilizes other molecules or incomplete breakdown pathways. Step 1: Contrast factors. 1. Oxygen requirement: Aerobic requires O2; Anaerobic does not. 2. ATP Yield: Aerobic produces ~30-32 ATP per glucose; Anaerobic produces 2 ATP. 3. End products: Aerobic results in CO2 and H2O; Anaerobic results in lactic acid or ethanol and CO2. 4. Location: Aerobic occurs in cytoplasm and mitochondria; Anaerobic occurs strictly in cytoplasm. 5. Process completion: Aerobic completes glycolysis, Krebs cycle, and oxidative phosphorylation; Anaerobic uses glycolysis and fermentation. Step 2: Identify similarities. Both processes begin with glycolysis, utilize glucose as a substrate, involve enzymatic regulation, and generate ATP to meet cellular metabolic demands. Interpretation: The choice between pathways is dictated by oxygen availability and the metabolic capacity of the organism or tissue.','\\text{Differences:} \\\\ 1. \\text{ Oxygen Requirement: Aerobic requires } O_2, \\text{ while Anaerobic is independent of } O_2. \\\\ 2. \\text{ ATP Production: Aerobic yields } \\sim 30-32 \\text{ ATP, whereas Anaerobic yields } 2 \\text{ ATP per glucose molecule.} \\\\ 3. \\text{ By-products: Aerobic yields } CO_2 \\text{ and } H_2O; \\text{ Anaerobic yields Lactic Acid or Ethanol and } CO_2. \\\\ 4. \\text{ Cellular Location: Aerobic occurs in cytosol and mitochondria; Anaerobic is restricted to the cytosol.} \\\\ 5. \\text{ Metabolic Pathways: Aerobic includes Glycolysis, Krebs Cycle, and ETC; Anaerobic involves Glycolysis and Fermentation.} \\\\ \\text{Similarities: Both processes initiate with glycolysis, utilize glucose as the primary fuel source, involve enzymatic redox reactions, and produce ATP to sustain life.}','5 key differences identified (O2, ATP yield, End-products, Location, Pathways) and similarities confirmed (shared glycolysis, substrate, and ATP production).','["Respiration Metabolism"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('16ecf920f0295710e8491f402e1fe62aaab847a8372030ae2044d7bd4cff3c23','End Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.1(a)','Explain schematically the experiments of Redi, Spallanzani and Pasteur and refute the hypothesis of spontaneous generation.','\\text{Explain schematically the experiments of Redi, Spallanzani and Pasteur and refute the hypothesis of spontaneous generation.}','1. Conceptual Analysis: The hypothesis of spontaneous generation posited that living organisms arise from non-living matter (abiogenesis). The three experiments were designed to test this by isolating potential life sources. Redi focused on macro-organisms (maggots/flies), Spallanzani on micro-organisms using heating, and Pasteur definitively refuted it using swan-neck flasks to separate air (vital force) from particulate contaminants.\n\n2. Step-by-Step Derivation:\n   - Redi: Placed meat in open, sealed, and gauze-covered jars. Maggots only appeared when flies could land on the meat, proving life comes from life (biogenesis).\n   - Spallanzani: Boiled broth in sealed flasks. No growth occurred, refuting spontaneous generation, though critics argued he destroyed a \'vital force\' in the air.\n   - Pasteur: Used swan-neck flasks that allowed air in but trapped particles (dust/microbes) in the neck curve. Broth remained sterile until the neck was tilted, allowing contact with particles. This isolated the variable of airborne contamination.\n\n3. Interpretation: The experiments successfully showed that life requires parental organisms (biogenesis). Pasteur\'s experiment, by allowing \'vital air\' while excluding particulates, proved that microbial growth is caused by existing microbes, effectively falsifying the spontaneous generation hypothesis.','\\text{1. Redi\'s Experiment: } \\text{Control (open jar) vs. Experimental (gauze-sealed jar). Result: Maggots only in open jars. Conclusion: Maggots arise from fly eggs, not decaying meat.} \\\\ \\text{2. Spallanzani\'s Experiment: } \\text{Boiled broth in sealed vs. unsealed flasks. Result: Sealed broth remained sterile. Conclusion: Microbial life is introduced from the environment.} \\\\ \\text{3. Pasteur\'s Experiment: } \\text{Swan-neck flasks prevent particle entry. Result: Sterile broth despite air access. Tipping the flask to contact trapped dust triggers growth. Conclusion: Life does not arise spontaneously; it is carried by airborne particulates.} \\\\ \\text{Final Conclusion: Biogenesis theory holds: } \\text{Omnis cellula e cellula (all cells from cells).}','Spontaneous generation is refuted by the evidence of biogenesis provided by Redi, Spallanzani, and definitively Pasteur.','["Origin of Life", "Spontaneous Generation"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e45226d0c3669c877320d68d8957971a820cae4bc174754f7b94bac8155e7b45','End Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.1(b)','Some special organelles are recruited in eukaryotic Cells, identify these organelles and discuss their functions.','\\text{Some special organelles are recruited in eukaryotic Cells, identify these organelles and discuss their functions.}','Eukaryotic cells recruit specialized organelles to compartmentalize biochemical processes, increasing efficiency. Key organelles include: 1. Nucleus, which stores genetic material and coordinates cell activities like replication and transcription. 2. Mitochondria, which perform aerobic respiration to generate ATP via oxidative phosphorylation. 3. Endoplasmic Reticulum (ER), which consists of the rough ER (protein synthesis/folding) and smooth ER (lipid synthesis/detoxification). 4. Golgi Apparatus, which modifies, sorts, and packages proteins and lipids for secretion or delivery to other organelles. 5. Lysosomes, which contain hydrolytic enzymes to degrade waste, pathogens, and cellular debris via autophagy or phagocytosis.','\\text{The key specialized organelles in eukaryotic cells are as follows:} \\\\ 1. \\text{Nucleus: Houses genomic DNA, regulating gene expression and replication.} \\\\ 2. \\text{Mitochondria: Responsible for energy production via the Citric Acid Cycle and Oxidative Phosphorylation.} \\\\ 3. \\text{Endoplasmic Reticulum: Rough ER involves protein synthesis and folding; Smooth ER handles lipid synthesis and calcium storage.} \\\\ 4. \\text{Golgi Apparatus: Modifies, sorts, and packages macromolecules for targeted cellular trafficking.} \\\\ 5. \\text{Lysosomes: Contain acid hydrolases to facilitate the degradation of intracellular materials and foreign pathogens.}','Nucleus, Mitochondria, Endoplasmic Reticulum, Golgi Apparatus, Lysosomes.','["Cell Biology", "Eukaryotic Organelles", "Programming Concepts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('b26c6e9c470d9dc05c9236dd3d31dc3193d3ce8a54b13ecce1a14a8a354ceb3b','End Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.2(a)','Justify, the Krebs cycle is an important event for aerobic respiration. How much ATP and $CO_(2)$ are generated in a complete cycle?','\\text{Justify, the Krebs cycle is an important event for aerobic respiration. How much ATP and } CO_{2} \\text{ are generated in a complete cycle?}','Conceptual analysis: The Krebs cycle (citric acid cycle) is central to aerobic respiration as it completes the oxidation of organic fuel derived from pyruvate. It generates high-energy electron carriers (NADH and FADH2) required for the electron transport chain (ETC) to produce the bulk of cellular ATP. \n\nStep-by-step derivation: \n1. Each cycle processes one Acetyl-CoA (2 carbons). \n2. Two carbon atoms are released as CO2 during the oxidative decarboxylation steps (isocitrate to alpha-ketoglutarate, and alpha-ketoglutarate to succinyl-CoA). \n3. One ATP (or GTP) is generated per turn via substrate-level phosphorylation. \n4. Three molecules of NADH and one molecule of FADH2 are also produced to fuel the ETC. \n\nInterpretation: The cycle effectively strips electrons from Acetyl-CoA to power ATP synthesis via oxidative phosphorylation, while producing CO2 as a byproduct.','1. \\text{Conceptual Significance: The Krebs cycle functions as the metabolic hub for aerobic respiration by harvesting high-energy electrons (NADH, FADH_{2}) from the breakdown of acetyl-CoA. These carriers facilitate the production of ATP via the electron transport chain.} \\\\ 2. \\text{Carbon Stoichiometry: Each turn of the cycle consumes one acetyl group (2C) and releases two molecules of } CO_{2} \\text{ during the decarboxylation reactions.} \\\\ 3. \\text{Energy Stoichiometry: Each turn results in the substrate-level phosphorylation of one ADP to one ATP (or GDP to GTP).} \\\\ 4. \\text{Calculation: Per one cycle (one acetyl-CoA): } ATP = 1, CO_{2} = 2.','1 ATP and 2 CO2 per cycle','["ATP Yield", "Krebs Cycle", "Respiration"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('cec48575390b2d70aceb180b4e8325750deb6ae865fb698ffc3a286c0eee3f66','End Semester','Unknown Subject (BE24101)','BE24101','3','2023','Q.2(b)','Photocatalytic water splitting converts sunlight and water into hydrogen, the fuel of the future. Justify the statement.','\\text{Photocatalytic water splitting converts sunlight and water into hydrogen, the fuel of the future. Justify the statement.}','Step 1: Conceptual Analysis. Photocatalytic water splitting is a process that utilizes solar energy to drive the non-spontaneous endothermic cleavage of water into hydrogen and oxygen. This leverages semiconductors to absorb photons with energies greater than the bandgap, creating electron-hole pairs that facilitate redox reactions. Step 2: Thermodynamic and Chemical Basis. The reaction 2H2O -> 2H2 + O2 requires an energy input of 237 kJ/mol. Photocatalysts reduce the activation energy by providing reaction sites for proton reduction (2H+ + 2e- -> H2) and water oxidation (2H2O + 4h+ -> O2 + 4H+). Step 3: Justification. Hydrogen is deemed the \'fuel of the future\' because its combustion produces only water, resulting in zero carbon emissions. By coupling this energy carrier with a renewable resource (sunlight) and an abundant feedstock (water), photocatalysis provides a sustainable closed-loop energy cycle. Step 4: Interpretation. The feasibility relies on catalyst efficiency, stability, and band-edge alignment, but fundamentally, it represents the bridge between intermittent solar energy and storable chemical fuel.','\\text{Step 1: Reaction Thermodynamics. The water splitting reaction is endergonic: } 2H_2O(l) \\rightarrow 2H_2(g) + O_2(g), \\Delta G^0 = 474 \\text{ kJ/mol}. \\text{ Step 2: Mechanism. Photons } (h\\nu \\ge E_g) \\text{ generate electron-hole pairs } (e^-/h^+): Photocatalyst + h\\nu \\rightarrow e^-_{CB} + h^+_{VB}. \\text{ Step 3: Redox Half-Reactions. Reduction: } 2H^+ + 2e^- \\rightarrow H_2 (E^0 = 0.00 \\text{ V vs SHE}); \\text{ Oxidation: } 2H_2O + 4h^+ \\rightarrow O_2 + 4H^+ (E^0 = 1.23 \\text{ V vs SHE}). \\text{ Step 4: Conclusion. Since } \\Delta G > 0, \\text{ light energy compensates for the Gibbs free energy requirement, storing solar energy in the chemical bonds of } H_2.','Photocatalytic water splitting is a sustainable mechanism that converts solar energy into high-energy chemical bonds (hydrogen), providing a clean, carbon-neutral fuel source that addresses the global energy crisis.','["Bioenergy", "Photocatalytic Water Splitting"]','analytical','0.98',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('bd91806ae5ca6606eb74af6adf809f3f31c87dd3790d0c01420e06f2fe98557e','End Semester','Unknown Subject (BE24101)','BE24101','2','2023','Q.3(a)','Describe the mechanism of enzyme action and five uses of enzymes in Industries.','\\text{Describe the mechanism of enzyme action and five uses of enzymes in Industries.}','The mechanism of enzyme action is primarily described by the Lock-and-Key hypothesis and the Induced Fit model. 1. Mechanism: Enzymes are biological catalysts that lower the activation energy of a reaction. The substrate binds to the enzyme\'s active site forming an Enzyme-Substrate (ES) complex. According to the Induced Fit model, the enzyme changes its conformation slightly to fit the substrate perfectly, facilitating the reaction to form an Enzyme-Product (EP) complex, and finally releasing the product while the enzyme remains unchanged. 2. Industrial uses: (a) Food industry: Amylases in bread making for sugar production and texture. (b) Detergent industry: Proteases and lipases to break down protein and fat-based stains. (c) Textile industry: Cellulases to soften fabrics and remove surface fibers. (d) Paper industry: Xylanases for bleaching pulp, reducing chlorine use. (e) Pharmaceutical industry: Streptokinase for dissolving blood clots in medical treatments.','\\text{Mechanism of Enzyme Action:} \\\\ 1. \\text{Enzyme + Substrate} \\rightleftharpoons \\text{ES Complex} \\rightleftharpoons \\text{EP Complex} \\rightleftharpoons \\text{Enzyme + Product} \\\\ \\text{The active site lowers the activation energy by stabilizing the transition state.} \\\\ \\text{Industrial Applications:} \\\\ 1. \\text{Food: Amylase for starch hydrolysis.} \\\\ 2. \\text{Detergents: Proteases for stain removal.} \\\\ 3. \\text{Textiles: Cellulases for bio-polishing.} \\\\ 4. \\text{Paper: Xylanases for eco-friendly bleaching.} \\\\ 5. \\text{Medicine: Streptokinase for thrombolysis.}','Mechanism: Enzyme-substrate complex formation lowering activation energy. Uses: Food (Amylase), Detergents (Protease), Textiles (Cellulase), Paper (Xylanase), Medicine (Streptokinase).','["Enzyme Mechanism", "Industrial Enzymes"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d3ee742eec82bfa51ca7c1b3f24c16243ed9e988f4465d9c3ecb77f4c669431d','End Semester','Unknown Subject (BE24101)','BE24101','5','2023','Q.3(b)','Explain the importance of Enzyme Immobilization. Is there any disadvantage to doing so?','\\text{Explain the importance of Enzyme Immobilization. Is there any disadvantage to doing so?}','Step 1: Conceptual Analysis of Enzyme Immobilization. Enzyme immobilization involves restricting the movement of enzymes in a defined space to improve their efficiency, stability, and reusability. It is critical for industrial applications where free enzymes are often cost-prohibitive and fragile. Step 2: Benefits. Key advantages include enhanced thermal and operational stability, the ability to reuse the biocatalyst over multiple cycles, easier separation of the product from the enzyme, and suitability for continuous process systems. Step 3: Disadvantages. Challenges include additional costs for immobilization materials, potential loss of enzyme activity due to chemical modifications, mass transfer resistance (diffusion limitations) between the substrate and the immobilized enzyme, and steric hindrance where the matrix blocks the active site. Step 4: Interpretation. While immobilization is essential for scalable biotechnological processes, trade-offs between stability and activity must be optimized for each specific reaction system.','1. \\text{Importance of Immobilization:} \\\\ \\bullet \\text{Reusability: Allows repeated use of biocatalysts, reducing costs.} \\\\ \\bullet \\text{Stability: Improves resistance to denaturation by temperature or pH.} \\\\ \\bullet \\text{Process Control: Facilitates easy separation of enzyme from product in continuous reactors.} \\\\ 2. \\text{Disadvantages:} \\\\ \\bullet \\text{Cost: Expense of support materials and immobilization chemistry.} \\\\ \\bullet \\text{Mass Transfer: Substrate diffusion to the active site may be hindered by the matrix.} \\\\ \\bullet \\text{Activity Loss: Denaturation or conformational changes during the attachment process.} \\\\ 3. \\text{Conclusion: Immobilization is a balance between operational longevity and kinetic efficiency.}','Enzyme immobilization provides crucial economic and stability benefits through reusability and improved robustness, though it introduces limitations regarding initial costs, potential activity loss, and mass transfer resistance.','["Enzyme Immobilization"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('80a57a393331476b19aa31004b056ba01ae4fa0a7704d748645f0788fcba662f','End Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.4(a)','What do you mean by circadian rhythm? Draw a labeled diagram of a Nerve cell.','\\text{What do you mean by circadian rhythm? Draw a labeled diagram of a Nerve cell.}','1. Circadian rhythm is the internal biological process that regulates the sleep-wake cycle and repeats roughly every 24 hours. It is controlled by the suprachiasmatic nucleus (SCN) in the hypothalamus, which responds to light and darkness in the environment. 2. A nerve cell (neuron) consists of three main parts: the cell body (soma), dendrites, and the axon. Dendrites receive signals, the soma processes them, and the axon transmits the electrical impulse away to other neurons or effector cells.','\\text{1. Circadian rhythm refers to endogenous, entrainable oscillations in biological processes that occur with a period of approximately 24 hours. These rhythms are regulated by the suprachiasmatic nucleus (SCN) which acts as the master biological clock by synchronizing with external light-dark cycles. \\\\ 2. A nerve cell (neuron) structure includes: } \\\\ \\text{ - Dendrites: Branching extensions receiving synaptic inputs.} \\\\ \\text{ - Cell Body (Soma): Contains the nucleus and organelles for metabolic maintenance.} \\\\ \\text{ - Axon: A long projection that transmits electrical impulses (action potentials) away from the cell body.} \\\\ \\text{ - Myelin Sheath: Fatty insulating layer around the axon.} \\\\ \\text{ - Axon Terminal: Site where neurotransmitters are released to signal the next cell.}','Circadian rhythm is a 24-hour internal biological clock. A neuron consists of dendrites, cell body, and an axon.','["Circadian Rhythm", "Nerve Cell"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('add7a88d0e3567a8fc4a7b365d738299383db8bf2117c5cf92ad54002d9e60df','End Semester','Unknown Subject (BE24101)','BE24101','1','2023','Q.4(b)','Discuss the different types of cell signaling. How the signals are amplified in a cell.','\\text{Discuss the different types of cell signaling. How the signals are amplified in a cell.}','Cell signaling is the process by which cells communicate with their environment and each other. 1. Types of Signaling: Endocrine (hormones travel via blood), Paracrine (local signaling to neighboring cells), Autocrine (cell signals to itself), and Juxtacrine (direct physical contact). 2. Signal Amplification: This process ensures a small extracellular stimulus produces a large intracellular response. It typically involves: (a) Enzyme cascades (e.g., kinase cascades where one enzyme activates multiple substrates), (b) Second messengers (e.g., cAMP, Ca2+, IP3, which diffuse rapidly to activate multiple downstream targets), and (c) Signal integration/divergence points.','\\text{1. Classification of Cell Signaling: } \\\\ \\text{a) Endocrine: Long-distance signaling via circulatory system (e.g., insulin).} \\\\ \\text{b) Paracrine: Local diffusion to nearby target cells (e.g., synaptic signaling).} \\\\ \\text{c) Autocrine: Cell responds to its own secreted ligands.} \\\\ \\text{d) Juxtacrine: Direct contact via membrane-bound proteins or gap junctions.} \\\\ \\text{2. Signal Amplification Mechanisms: } \\\\ \\text{Amplification occurs when an initial stimulus (ligand-receptor binding) activates multiple downstream effectors. Mathematically, if } n \\text{ is the number of secondary molecules activated per step, a cascade of } k \\text{ steps results in } n^k \\text{ amplification. Key mechanisms include:} \\\\ \\text{a) Enzymatic Cascades: One active protein kinase phosphorylates many target proteins.} \\\\ \\text{b) Second Messengers: Generation of molecules like cAMP or } Ca^{2+} \\text{ allows for broad, rapid signaling dissemination.} \\\\ \\text{c) G-protein coupled receptors (GPCRs): One receptor can activate multiple G-proteins before becoming desensitized.}','Cell signaling occurs via endocrine, paracrine, autocrine, and juxtacrine pathways; amplification is achieved primarily through enzyme cascades and second messenger systems.','["Cell Signaling", "Signal Amplification"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4806720dc8e69a11207c5ddca91dca21992a71b61c6fd39c67708719eeeeb312','End Semester','Unknown Subject (BE24101)','BE24101','5','2023','Q.5(a)','What do you understand by the central dogma of Molecular Biology? How this knowledge is useful in genetic engineering.','\\text{What do you understand by the central dogma of Molecular Biology? How this knowledge is useful in genetic engineering.}','The central dogma of molecular biology describes the directional flow of genetic information: DNA to RNA to Protein. Step 1: DNA stores information (replication). Step 2: Information is transcribed into mRNA (transcription). Step 3: mRNA is translated into functional polypeptides (translation). In genetic engineering, this dogma is crucial because it defines the control points for expression. By manipulating DNA sequences (e.g., using recombinant DNA), scientists can program cells to synthesize specific proteins. We use knowledge of transcription factors to initiate expression, codons to optimize protein production, and post-translational modification pathways to ensure the protein is functional.','\\text{The central dogma is defined by the process: DNA} \\xrightarrow{\\text{transcription}} \\text{RNA} \\xrightarrow{\\text{translation}} \\text{Protein. In genetic engineering, this framework allows for the targeted modification of biological systems by: 1. DNA Manipulation: Inserting exogenous genes via vectors. 2. Transcription Control: Utilizing promoters and enhancers to regulate gene expression. 3. Translation Optimization: Using codon bias and synthetic RBS for maximal protein yield. 4. Application: Production of therapeutic proteins like insulin and industrial enzymes.}','The central dogma (DNA -> RNA -> Protein) provides the blueprint for genetic manipulation; engineering involves altering DNA to control the flow of information for the production of desired biological products.','["Central Dogma", "Genetic Engineering"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('5ca21e22f7dc1f144809286d0087ad3332b612ef65fa3811b7284d96bbe6b47e','End Semester','Unknown Subject (BE24101)','BE24101','5','2023','Q.5(b)','Differentiate between PCR and ELISA.','\\text{Differentiate between PCR and ELISA.}','1. Definition: PCR (Polymerase Chain Reaction) is a molecular technique used to amplify specific segments of DNA, while ELISA (Enzyme-Linked Immunosorbent Assay) is an immunological technique used to detect and quantify proteins, antibodies, or antigens. 2. Target: PCR targets nucleic acids (DNA/RNA), whereas ELISA targets proteins or antigens. 3. Mechanism: PCR relies on thermal cycling and DNA polymerase to replicate DNA, whereas ELISA relies on antigen-antibody binding and an enzyme-linked colorimetric reaction. 4. Sensitivity: Both are highly sensitive, but PCR is generally more sensitive for detecting minute amounts of genetic material, whereas ELISA is optimized for high-throughput protein quantification. 5. Applications: PCR is used for diagnostics (e.g., COVID-19 PCR), forensics, and genetic research. ELISA is used for diagnostic tests (e.g., HIV, pregnancy tests) and biomarker analysis.','\\begin{enumerate} \\item \\textbf{Mechanism:} PCR utilizes thermal cycling for DNA denaturation, annealing, and extension to amplify DNA sequences. ELISA utilizes the specific binding between antigens and antibodies followed by an enzyme-linked substrate reaction to produce a detectable signal. \\item \\textbf{Target Molecule:} PCR detects DNA or RNA sequences. ELISA detects proteins, peptides, or antibodies. \\item \\textbf{Principle:} PCR relies on DNA polymerase activity. ELISA relies on the immunological affinity between antigens and antibodies. \\item \\textbf{Detection Basis:} PCR yields an amplified DNA product (visualized via gel electrophoresis or fluorescence). ELISA yields a colorimetric or fluorescent signal proportional to the concentration of the analyte. \\end{enumerate}','PCR amplifies DNA using thermal cycling, whereas ELISA detects proteins or antigens using antigen-antibody interactions and enzyme signaling.','["Biotechnology Techniques", "ELISA", "PCR"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);